const ordinalNumber = (dirtyNumber, options) => {
  const unit = String(options?.unit);
  const number = Number(dirtyNumber);
  let suffix;

  /** Though it's an incorrect ordinal form of a date we use it here for consistency with other similar locales (ru, uk)
   *  For date-month combinations should be used `d` formatter.
   *  Correct:   `d MMMM` (4 –≤–Ķ—Ä–į—Ā–Ĺ—Ź)
   *  Incorrect: `do MMMM` (4-–≥–į –≤–Ķ—Ä–į—Ā–Ĺ—Ź)
   *
   *  But following the consistency leads to mistakes for literal uses of `do` formatter (ordinal day of month).
   *  So for phrase "5th day of month" (`do –ī–∑–Ķ–Ĺ—Ć –ľ–Ķ—Ā—Ź—Ü–į`)
   *  library will produce:            `5-–≥–į –ī–∑–Ķ–Ĺ—Ć –ľ–Ķ—Ā—Ź—Ü–į`
   *  but correct spelling should be:  `5-—č –ī–∑–Ķ–Ĺ—Ć –ľ–Ķ—Ā—Ź—Ü–į`
   *
   *  So I guess there should be a stand-alone and a formatting version of "day of month" formatters
   */
  if (unit === "date") {
    suffix = "-–≥–į";
  } else if (unit === "hour" || unit === "minute" || unit === "second") {
    suffix = "-—Ź";
  } else {
    suffix =
      (number % 10 === 2 || number % 10 === 3) &&
      number % 100 !== 12 &&
      number % 100 !== 13
        ? "-—Ė"
        : "-—č";
  }

  return number + suffix;
};

export const localize = {
  ordinalNumber,

  era: buildLocalizeFn({
    values: eraValues,
    defaultWidth: "wide",
  }),

  quarter: buildLocalizeFn({
    values: quarterValues,
    defaultWidth: "wide",
    argumentCallback: (quarter) => quarter - 1,
  }),

  month: buildLocalizeFn({
    values: monthValues,
    defaultWidth: "wide",
    formattingValues: formattingMonthValues,
    defaultFormattingWidth: "wide",
  }),

  day: buildLocalizeFn({
    values: dayValues,
    defaultWidth: "wide",
  }),

  dayPeriod: buildLocalizeFn({
    values: dayPeriodValues,
    defaultWidth: "any",
    formattingValues: formattingDayPeriodValues,
    defaultFormattingWidth: "wide",
  }),
};
