import { buildLocalizeFn } from "../../_lib/buildLocalizeFn.js";

const eraValues = {
  narrow: ["–Ņ—Ä.–Ĺ.–Ķ.", "–Ĺ.–Ķ."],
  abbreviated: ["–Ņ—Ä–Ķ–ī –Ĺ. –Ķ.", "–Ĺ. –Ķ."],
  wide: ["–Ņ—Ä–Ķ–ī –Ĺ–į—ą–į—ā–į –Ķ—Ä–į", "–Ĺ–į—ą–į—ā–į –Ķ—Ä–į"],
};

const quarterValues = {
  narrow: ["1", "2", "3", "4"],
  abbreviated: ["1-–≤–ł –ļ–≤.", "2-—Ä–ł –ļ–≤.", "3-—ā–ł –ļ–≤.", "4-—ā–ł –ļ–≤."],
  wide: ["1-–≤–ł –ļ–≤–į—Ä—ā–į–Ľ", "2-—Ä–ł –ļ–≤–į—Ä—ā–į–Ľ", "3-—ā–ł –ļ–≤–į—Ä—ā–į–Ľ", "4-—ā–ł –ļ–≤–į—Ä—ā–į–Ľ"],
};

const monthValues = {
  abbreviated: [
    "—ė–į–Ĺ",
    "—Ą–Ķ–≤",
    "–ľ–į—Ä",
    "–į–Ņ—Ä",
    "–ľ–į—ė",
    "—ė—É–Ĺ",
    "—ė—É–Ľ",
    "–į–≤–≥",
    "—Ā–Ķ–Ņ—ā",
    "–ĺ–ļ—ā",
    "–Ĺ–ĺ–Ķ–ľ",
    "–ī–Ķ–ļ",
  ],

  wide: [
    "—ė–į–Ĺ—É–į—Ä–ł",
    "—Ą–Ķ–≤—Ä—É–į—Ä–ł",
    "–ľ–į—Ä—ā",
    "–į–Ņ—Ä–ł–Ľ",
    "–ľ–į—ė",
    "—ė—É–Ĺ–ł",
    "—ė—É–Ľ–ł",
    "–į–≤–≥—É—Ā—ā",
    "—Ā–Ķ–Ņ—ā–Ķ–ľ–≤—Ä–ł",
    "–ĺ–ļ—ā–ĺ–ľ–≤—Ä–ł",
    "–Ĺ–ĺ–Ķ–ľ–≤—Ä–ł",
    "–ī–Ķ–ļ–Ķ–ľ–≤—Ä–ł",
  ],
};

const dayValues = {
  narrow: ["–Ě", "–ü", "–í", "–°", "–ß", "–ü", "–°"],
  short: ["–Ĺ–Ķ", "–Ņ–ĺ", "–≤—ā", "—Ā—Ä", "—á–Ķ", "–Ņ–Ķ", "—Ā–į"],
  abbreviated: ["–Ĺ–Ķ–ī", "–Ņ–ĺ–Ĺ", "–≤—ā–ĺ", "—Ā—Ä–Ķ", "—á–Ķ—ā", "–Ņ–Ķ—ā", "—Ā–į–Ī"],
  wide: [
    "–Ĺ–Ķ–ī–Ķ–Ľ–į",
    "–Ņ–ĺ–Ĺ–Ķ–ī–Ķ–Ľ–Ĺ–ł–ļ",
    "–≤—ā–ĺ—Ä–Ĺ–ł–ļ",
    "—Ā—Ä–Ķ–ī–į",
    "—á–Ķ—ā–≤—Ä—ā–ĺ–ļ",
    "–Ņ–Ķ—ā–ĺ–ļ",
    "—Ā–į–Ī–ĺ—ā–į",
  ],
};

const dayPeriodValues = {
  wide: {
    am: "–Ņ—Ä–Ķ—ā–Ņ–Ľ–į–ī–Ĺ–Ķ",
    pm: "–Ņ–ĺ–Ņ–Ľ–į–ī–Ĺ–Ķ",
    midnight: "–Ņ–ĺ–Ľ–Ĺ–ĺ—ú",
    noon: "–Ĺ–į–Ņ–Ľ–į–ī–Ĺ–Ķ",
    morning: "–Ĺ–į—É—ā—Ä–ĺ",
    afternoon: "–Ņ–ĺ–Ņ–Ľ–į–ī–Ĺ–Ķ",
    evening: "–Ĺ–į–≤–Ķ—á–Ķ—Ä",
    night: "–Ĺ–ĺ—ú–Ķ",
  },
};

const ordinalNumber = (dirtyNumber, _options) => {
  const number = Number(dirtyNumber);

  const rem100 = number % 100;
  if (rem100 > 20 || rem100 < 10) {
    switch (rem100 % 10) {
      case 1:
        return number + "-–≤–ł";
      case 2:
        return number + "-—Ä–ł";
      case 7:
      case 8:
        return number + "-–ľ–ł";
    }
  }
  return number + "-—ā–ł";
};

export const localize = {
  ordinalNumber,

  era: buildLocalizeFn({
    values: eraValues,
    defaultWidth: "wide",
  }),

  quarter: buildLocalizeFn({
    values: quarterValues,
    defaultWidth: "wide",
    argumentCallback: (quarter) => quarter - 1,
  }),

  month: buildLocalizeFn({
    values: monthValues,
    defaultWidth: "wide",
  }),

  day: buildLocalizeFn({
    values: dayValues,
    defaultWidth: "wide",
  }),

  dayPeriod: buildLocalizeFn({
    values: dayPeriodValues,
    defaultWidth: "wide",
  }),
};
