const formatRelativeLocale = {
  lastWeek: "'o' eeee 'pasado √°' LT",
  yesterday: "'onte √°' p",
  today: "'hoxe √°' p",
  tomorrow: "'ma√Ī√° √°' p",
  nextWeek: "eeee '√°' p",
  other: "P",
};

const formatRelativeLocalePlural = {
  lastWeek: "'o' eeee 'pasado √°s' p",
  yesterday: "'onte √°s' p",
  today: "'hoxe √°s' p",
  tomorrow: "'ma√Ī√° √°s' p",
  nextWeek: "eeee '√°s' p",
  other: "P",
};

export const formatRelative = (token, date, _baseDate, _options) => {
  if (date.getHours() !== 1) {
    return formatRelativeLocalePlural[token];
  }
  return formatRelativeLocale[token];
};
