import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern =
  /^(\d+)(-?(–Ķ|—Ź|–≥–į|—Ė|—č|–į–Ķ|–į—Ź|—Ź—Ź|—ą—č|–≥—Ė|—Ü—Ė|—ā—č|–ľ—č))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((–ī–į )?–Ĺ\.?\s?—ć\.?)/i,
  abbreviated: /^((–ī–į )?–Ĺ\.?\s?—ć\.?)/i,
  wide: /^(–ī–į –Ĺ–į—ą–į–Ļ —ć—Ä—č|–Ĺ–į—ą–į–Ļ —ć—Ä—č|–Ĺ–į—ą–į —ć—Ä–į)/i,
};
const parseEraPatterns = {
  any: [/^–ī/i, /^–Ĺ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[—č—Ė]?)? –ļ–≤.?/i,
  wide: /^[1234](-?[—č—Ė]?)? –ļ–≤–į—Ä—ā–į–Ľ/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[—Ā–Ľ–ļ–ľ—á–∂–≤]/i,
  abbreviated:
    /^(—Ā—ā—É–ī–∑|–Ľ—é—ā|—Ā–į–ļ|–ļ—Ä–į—Ā|–ľ–į[–Ļ—Ź]|—á—ć—Ä–≤|–Ľ—Ė–Ņ|–∂–Ĺ|–≤–Ķ—Ä|–ļ–į—Ā—ā—Ä|–Ľ—Ė—Ā—ā|—Ā–Ĺ–Ķ–∂)\.?/i,
  wide: /^(—Ā—ā—É–ī–∑–Ķ–Ĺ[—Ć—Ź]|–Ľ—é—ā(—č|–į–≥–į)|—Ā–į–ļ–į–≤—Ė–ļ–į?|–ļ—Ä–į—Ā–į–≤—Ė–ļ–į?|–ľ–į[–Ļ—Ź]|—á—ć—Ä–≤–Ķ–Ĺ[—Ć—Ź]|–Ľ—Ė–Ņ–Ķ–Ĺ[—Ć—Ź]|–∂–Ĺ—Ė(–≤–Ķ–Ĺ—Ć|—ě–Ĺ—Ź)|–≤–Ķ—Ä–į—Ā(–Ķ–Ĺ—Ć|–Ĺ—Ź)|–ļ–į—Ā—ā—Ä—č—á–Ĺ—Ė–ļ–į?|–Ľ—Ė—Ā—ā–į–Ņ–į–ī–į?|—Ā–Ĺ–Ķ–∂(–į–Ĺ—Ć|–Ĺ—Ź))/i,
};
const parseMonthPatterns = {
  narrow: [
    /^—Ā/i,
    /^–Ľ/i,
    /^—Ā/i,
    /^–ļ/i,
    /^–ľ/i,
    /^—á/i,
    /^–Ľ/i,
    /^–∂/i,
    /^–≤/i,
    /^–ļ/i,
    /^–Ľ/i,
    /^—Ā/i,
  ],

  any: [
    /^—Ā—ā/i,
    /^–Ľ—é/i,
    /^—Ā–į/i,
    /^–ļ—Ä/i,
    /^–ľ–į/i,
    /^—á/i,
    /^–Ľ—Ė–Ņ/i,
    /^–∂/i,
    /^–≤/i,
    /^–ļ–į/i,
    /^–Ľ—Ė—Ā/i,
    /^—Ā–Ĺ/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[–Ĺ–Ņ–į—Ā—á]/i,
  short: /^(–Ĺ–ī|–Ĺ—Ź|–Ņ–Ĺ|–Ņ–į|–į—ě|–į—ā|—Ā—Ä|—Ā–Ķ|—á—Ü|—á–į|–Ņ—ā|–Ņ—Ź|—Ā–Ī|—Ā—É)\.?/i,
  abbreviated: /^(–Ĺ—Ź–ī–∑?|–Ĺ–ī–∑|–Ņ–Ĺ–ī|–Ņ–į–Ĺ|–į—ě—ā|—Ā—Ä–ī|—Ā–Ķ—Ä|—á—Ü–≤|—á–į—Ü|–Ņ—ā–Ĺ|–Ņ—Ź—ā|—Ā—É–Ī).?/i,
  wide: /^(–Ĺ—Ź–ī–∑–Ķ–Ľ[—Ź—Ė]|–Ņ–į–Ĺ—Ź–ī–∑–Ķ–Ľ(–į–ļ|–ļ–į)|–į—ě—ā–ĺ—Ä(–į–ļ|–ļ–į)|—Ā–Ķ—Ä–į–ī[–į—č]|—á–į—Ü–≤(–Ķ—Ä|—Ź—Ä–≥–į)|–Ņ—Ź—ā–Ĺ—Ė—Ü[–į—č]|—Ā—É–Ī–ĺ—ā[–į—č])/i,
};
const parseDayPatterns = {
  narrow: [/^–Ĺ/i, /^–Ņ/i, /^–į/i, /^—Ā/i, /^—á/i, /^–Ņ/i, /^—Ā/i],
  any: [/^–Ĺ/i, /^–Ņ[–į–Ĺ]/i, /^–į/i, /^—Ā[–Ķ—Ä]/i, /^—á/i, /^–Ņ[—Ź—ā]/i, /^—Ā[—É–Ī]/i],
};

const matchDayPeriodPatterns = {
  narrow: /^([–ī–Ņ]–Ņ|–Ņ–ĺ—ě–Ĺ\.?|–Ņ–ĺ—ě–ī\.?|—Ä–į–Ĺ\.?|–ī–∑–Ķ–Ĺ—Ć|–ī–Ĺ—Ź|–≤–Ķ—á\.?|–Ĺ–ĺ—á—č?)/i,
  abbreviated: /^([–ī–Ņ]–Ņ|–Ņ–ĺ—ě–Ĺ\.?|–Ņ–ĺ—ě–ī\.?|—Ä–į–Ĺ\.?|–ī–∑–Ķ–Ĺ—Ć|–ī–Ĺ—Ź|–≤–Ķ—á\.?|–Ĺ–ĺ—á—č?)/i,
  wide: /^([–ī–Ņ]–Ņ|–Ņ–ĺ—ě–Ĺ–į—á|–Ņ–ĺ—ě–ī–∑–Ķ–Ĺ—Ć|—Ä–į–Ĺ—Ė—Ü[–į—č]|–ī–∑–Ķ–Ĺ—Ć|–ī–Ĺ—Ź|–≤–Ķ—á–į—Ä–į?|–Ĺ–ĺ—á—č?)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^–ī–Ņ/i,
    pm: /^–Ņ–Ņ/i,
    midnight: /^–Ņ–ĺ—ě–Ĺ/i,
    noon: /^–Ņ–ĺ—ě–ī/i,
    morning: /^—Ä/i,
    afternoon: /^–ī[–∑–Ĺ]/i,
    evening: /^–≤/i,
    night: /^–Ĺ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
