const suffixes = {
  1: "-inci",
  5: "-inci",
  8: "-inci",
  70: "-inci",
  80: "-inci",
  2: "-nci",
  7: "-nci",
  20: "-nci",
  50: "-nci",
  3: "-√ľnc√ľ",
  4: "-√ľnc√ľ",
  100: "-√ľnc√ľ",
  6: "-ncńĪ",
  9: "-uncu",
  10: "-uncu",
  30: "-uncu",
  60: "-ńĪncńĪ",
  90: "-ńĪncńĪ",
};

const getSuffix = (number) => {
  if (number === 0) {
    // special case for zero
    return number + "-ńĪncńĪ";
  }

  const a = number % 10;
  const b = (number % 100) - a;
  const c = number >= 100 ? 100 : null;

  if (suffixes[a]) {
    return suffixes[a];
  } else if (suffixes[b]) {
    return suffixes[b];
  } else if (c !== null) {
    return suffixes[c];
  }
  return "";
};

const ordinalNumber = (dirtyNumber, _options) => {
  const number = Number(dirtyNumber);
  const suffix = getSuffix(number);

  return number + suffix;
};

