import { isSameWeek } from "../../../isSameWeek.js";

const weekdays = [
  "–Ĺ–Ķ–ī–Ķ–Ľ–į",
  "–Ņ–ĺ–Ĺ–Ķ–ī–Ķ–Ľ–Ĺ–ł–ļ",
  "–≤—ā–ĺ—Ä–Ĺ–ł–ļ",
  "—Ā—Ä–Ķ–ī–į",
  "—á–Ķ—ā–≤—Ä—ā–ĺ–ļ",
  "–Ņ–Ķ—ā–ĺ–ļ",
  "—Ā–į–Ī–ĺ—ā–į",
];

function lastWeek(day) {
  const weekday = weekdays[day];

  switch (day) {
    case 0:
    case 3:
    case 6:
      return "'–ľ–ł–Ĺ–į—ā–į—ā–į " + weekday + " –≤–ĺ' p";
    case 1:
    case 2:
    case 4:
    case 5:
      return "'–ľ–ł–Ĺ–į—ā–ł–ĺ—ā " + weekday + " –≤–ĺ' p";
  }
}

function thisWeek(day) {
  const weekday = weekdays[day];

  switch (day) {
    case 0:
    case 3:
    case 6:
      return "'–ĺ–≤–į " + weekday + " –≤o' p";
    case 1:
    case 2:
    case 4:
    case 5:
      return "'–ĺ–≤–ĺ—ė " + weekday + " –≤o' p";
  }
}

function nextWeek(day) {
  const weekday = weekdays[day];

  switch (day) {
    case 0:
    case 3:
    case 6:
      return "'—Ā–Ľ–Ķ–ī–Ĺ–į—ā–į " + weekday + " –≤o' p";
    case 1:
    case 2:
    case 4:
    case 5:
      return "'—Ā–Ľ–Ķ–ī–Ĺ–ł–ĺ—ā " + weekday + " –≤o' p";
  }
}

const formatRelativeLocale = {
  lastWeek: (date, baseDate, options) => {
    const day = date.getDay();
    if (isSameWeek(date, baseDate, options)) {
      return thisWeek(day);
    } else {
      return lastWeek(day);
    }
  },
  yesterday: "'–≤—á–Ķ—Ä–į –≤–ĺ' p",
  today: "'–ī–Ķ–Ĺ–Ķ—Ā –≤–ĺ' p",
  tomorrow: "'—É—ā—Ä–Ķ –≤–ĺ' p",
  nextWeek: (date, baseDate, options) => {
    const day = date.getDay();
    if (isSameWeek(date, baseDate, options)) {
      return thisWeek(day);
    } else {
      return nextWeek(day);
    }
  },
  other: "P",
};

export const formatRelative = (token, date, baseDate, options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date, baseDate, options);
  }

  return format;
};
