const ordinalNumber = (dirtyNumber, options) => {
  const number = Number(dirtyNumber);

  switch (options?.unit) {
    case "date":
      return number.toString() + "śó•";
    case "hour":
      return number.toString() + "śó∂";
    case "minute":
      return number.toString() + "ŚąÜ";
    case "second":
      return number.toString() + "Áßí";
    default:
      return "Á¨¨ " + number.toString();
  }
};

