import { isSameWeek } from "../../../isSameWeek.js";
import { toDate } from "../../../toDate.js";

const accusativeWeekdays = [
  "–Ĺ–Ķ–ī—Ė–Ľ—é",
  "–Ņ–ĺ–Ĺ–Ķ–ī—Ė–Ľ–ĺ–ļ",
  "–≤—Ė–≤—ā–ĺ—Ä–ĺ–ļ",
  "—Ā–Ķ—Ä–Ķ–ī—É",
  "—á–Ķ—ā–≤–Ķ—Ä",
  "–Ņ‚Äô—Ź—ā–Ĺ–ł—Ü—é",
  "—Ā—É–Ī–ĺ—ā—É",
];

function lastWeek(day) {
  const weekday = accusativeWeekdays[day];

  switch (day) {
    case 0:
    case 3:
    case 5:
    case 6:
      return "'—É –ľ–ł–Ĺ—É–Ľ—É " + weekday + " –ĺ' p";
    case 1:
    case 2:
    case 4:
      return "'—É –ľ–ł–Ĺ—É–Ľ–ł–Ļ " + weekday + " –ĺ' p";
  }
}

function thisWeek(day) {
  const weekday = accusativeWeekdays[day];

  return "'—É " + weekday + " –ĺ' p";
}

function nextWeek(day) {
  const weekday = accusativeWeekdays[day];

  switch (day) {
    case 0:
    case 3:
    case 5:
    case 6:
      return "'—É –Ĺ–į—Ā—ā—É–Ņ–Ĺ—É " + weekday + " –ĺ' p";
    case 1:
    case 2:
    case 4:
      return "'—É –Ĺ–į—Ā—ā—É–Ņ–Ĺ–ł–Ļ " + weekday + " –ĺ' p";
  }
}

const lastWeekFormat = (dirtyDate, baseDate, options) => {
  const date = toDate(dirtyDate);
  const day = date.getDay();

  if (isSameWeek(date, baseDate, options)) {
    return thisWeek(day);
  } else {
    return lastWeek(day);
  }
};

const nextWeekFormat = (dirtyDate, baseDate, options) => {
  const date = toDate(dirtyDate);
  const day = date.getDay();
  if (isSameWeek(date, baseDate, options)) {
    return thisWeek(day);
  } else {
    return nextWeek(day);
  }
};

const formatRelativeLocale = {
  lastWeek: lastWeekFormat,
  yesterday: "'–≤—á–ĺ—Ä–į –ĺ' p",
  today: "'—Ā—Ć–ĺ–≥–ĺ–ī–Ĺ—Ė –ĺ' p",
  tomorrow: "'–∑–į–≤—ā—Ä–į –ĺ' p",
  nextWeek: nextWeekFormat,
  other: "P",
};

export const formatRelative = (token, date, baseDate, options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date, baseDate, options);
  }

  return format;
};
