import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)\./i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(–Ņ—Ä\.–Ĺ\.–Ķ\.|–ź–Ē)/i,
  abbreviated: /^(–Ņ—Ä\.\s?–•—Ä\.|–Ņ–ĺ\.\s?–•—Ä\.)/i,
  wide: /^(–ü—Ä–Ķ –•—Ä–ł—Ā—ā–į|–Ņ—Ä–Ķ –Ĺ–ĺ–≤–Ķ –Ķ—Ä–Ķ|–ü–ĺ—Ā–Ľ–Ķ –•—Ä–ł—Ā—ā–į|–Ĺ–ĺ–≤–į –Ķ—Ä–į)/i,
};
const parseEraPatterns = {
  any: [/^–Ņ—Ä/i, /^(–Ņ–ĺ|–Ĺ–ĺ–≤–į)/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234]\.\s?–ļ–≤\.?/i,
  wide: /^[1234]\. –ļ–≤–į—Ä—ā–į–Ľ/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^(10|11|12|[123456789])\./i,
  abbreviated: /^(—ė–į–Ĺ|—Ą–Ķ–Ī|–ľ–į—Ä|–į–Ņ—Ä|–ľ–į—ė|—ė—É–Ĺ|—ė—É–Ľ|–į–≤–≥|—Ā–Ķ–Ņ|–ĺ–ļ—ā|–Ĺ–ĺ–≤|–ī–Ķ—Ü)/i,
  wide: /^((—ė–į–Ĺ—É–į—Ä|—ė–į–Ĺ—É–į—Ä–į)|(—Ą–Ķ–Ī—Ä—É–į—Ä|—Ą–Ķ–Ī—Ä—É–į—Ä–į)|(–ľ–į—Ä—ā|–ľ–į—Ä—ā–į)|(–į–Ņ—Ä–ł–Ľ|–į–Ņ—Ä–ł–Ľ–į)|(–ľ—ė–į|–ľ–į—ė–į)|(—ė—É–Ĺ|—ė—É–Ĺ–į)|(—ė—É–Ľ|—ė—É–Ľ–į)|(–į–≤–≥—É—Ā—ā|–į–≤–≥—É—Ā—ā–į)|(—Ā–Ķ–Ņ—ā–Ķ–ľ–Ī–į—Ä|—Ā–Ķ–Ņ—ā–Ķ–ľ–Ī—Ä–į)|(–ĺ–ļ—ā–ĺ–Ī–į—Ä|–ĺ–ļ—ā–ĺ–Ī—Ä–į)|(–Ĺ–ĺ–≤–Ķ–ľ–Ī–į—Ä|–Ĺ–ĺ–≤–Ķ–ľ–Ī—Ä–į)|(–ī–Ķ—Ü–Ķ–ľ–Ī–į—Ä|–ī–Ķ—Ü–Ķ–ľ–Ī—Ä–į))/i,
};
const parseMonthPatterns = {
  narrow: [
    /^1/i,
    /^2/i,
    /^3/i,
    /^4/i,
    /^5/i,
    /^6/i,
    /^7/i,
    /^8/i,
    /^9/i,
    /^10/i,
    /^11/i,
    /^12/i,
  ],

  any: [
    /^—ė–į/i,
    /^—Ą/i,
    /^–ľ–į—Ä/i,
    /^–į–Ņ/i,
    /^–ľ–į—ė/i,
    /^—ė—É–Ĺ/i,
    /^—ė—É–Ľ/i,
    /^–į–≤–≥/i,
    /^—Ā/i,
    /^–ĺ/i,
    /^–Ĺ/i,
    /^–ī/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[–Ņ—É—Ā—á–Ĺ]/i,
  short: /^(–Ĺ–Ķ–ī|–Ņ–ĺ–Ĺ|—É—ā–ĺ|—Ā—Ä–Ķ|—á–Ķ—ā|–Ņ–Ķ—ā|—Ā—É–Ī)/i,
  abbreviated: /^(–Ĺ–Ķ–ī|–Ņ–ĺ–Ĺ|—É—ā–ĺ|—Ā—Ä–Ķ|—á–Ķ—ā|–Ņ–Ķ—ā|—Ā—É–Ī)/i,
  wide: /^(–Ĺ–Ķ–ī–Ķ—ô–į|–Ņ–ĺ–Ĺ–Ķ–ī–Ķ—ô–į–ļ|—É—ā–ĺ—Ä–į–ļ|—Ā—Ä–Ķ–ī–į|—á–Ķ—ā–≤—Ä—ā–į–ļ|–Ņ–Ķ—ā–į–ļ|—Ā—É–Ī–ĺ—ā–į)/i,
};
const parseDayPatterns = {
  narrow: [/^–Ņ/i, /^—É/i, /^—Ā/i, /^—á/i, /^–Ņ/i, /^—Ā/i, /^–Ĺ/i],
  any: [/^–Ĺ–Ķ–ī/i, /^–Ņ–ĺ–Ĺ/i, /^—É—ā–ĺ/i, /^—Ā—Ä–Ķ/i, /^—á–Ķ—ā/i, /^–Ņ–Ķ—ā/i, /^—Ā—É–Ī/i],
};

const matchDayPeriodPatterns = {
  any: /^(–į–ľ|–Ņ–ľ|–Ņ–ĺ–Ĺ–ĺ—õ|(–Ņ–ĺ)?–Ņ–ĺ–ī–Ĺ–Ķ|—É–≤–Ķ—á–Ķ|–Ĺ–ĺ—õ—É|–Ņ–ĺ—Ā–Ľ–Ķ –Ņ–ĺ–ī–Ĺ–Ķ|—É—ė—É—ā—Ä—É)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^a/i,
    pm: /^p/i,
    midnight: /^–Ņ–ĺ–Ĺ–ĺ/i,
    noon: /^–Ņ–ĺ–ī/i,
    morning: /—É—ė—É—ā—Ä—É/i,
    afternoon: /(–Ņ–ĺ—Ā–Ľ–Ķ\s|–Ņ–ĺ)+–Ņ–ĺ–ī–Ĺ–Ķ/i,
    evening: /(—É–≤–Ķ—á–Ķ)/i,
    night: /(–Ĺ–ĺ—õ—É)/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
