const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "—Ā–Ķ–ļ—É–Ĺ–ī —Ö“Į—Ä—ć—Ö–≥“Į–Ļ",
    other: "{{count}} —Ā–Ķ–ļ—É–Ĺ–ī —Ö“Į—Ä—ć—Ö–≥“Į–Ļ",
  },

  xSeconds: {
    one: "1 —Ā–Ķ–ļ—É–Ĺ–ī",
    other: "{{count}} —Ā–Ķ–ļ—É–Ĺ–ī",
  },

  halfAMinute: "—Ö–į–≥–į—Ā –ľ–ł–Ĺ—É—ā",

  lessThanXMinutes: {
    one: "–ľ–ł–Ĺ—É—ā —Ö“Į—Ä—ć—Ö–≥“Į–Ļ",
    other: "{{count}} –ľ–ł–Ĺ—É—ā —Ö“Į—Ä—ć—Ö–≥“Į–Ļ",
  },

  xMinutes: {
    one: "1 –ľ–ł–Ĺ—É—ā",
    other: "{{count}} –ľ–ł–Ĺ—É—ā",
  },

  aboutXHours: {
    one: "–ĺ–Ļ—Ä–ĺ–Ľ—Ü–ĺ–ĺ–≥–ĺ–ĺ—Ä 1 —Ü–į–≥",
    other: "–ĺ–Ļ—Ä–ĺ–Ľ—Ü–ĺ–ĺ–≥–ĺ–ĺ—Ä {{count}} —Ü–į–≥",
  },

  xHours: {
    one: "1 —Ü–į–≥",
    other: "{{count}} —Ü–į–≥",
  },

  xDays: {
    one: "1 ”©–ī”©—Ä",
    other: "{{count}} ”©–ī”©—Ä",
  },

  aboutXWeeks: {
    one: "–ĺ–Ļ—Ä–ĺ–Ľ—Ü–ĺ–ĺ–≥–ĺ–ĺ—Ä 1 –ī–ĺ–Ľ–ĺ–ĺ —Ö–ĺ–Ĺ–ĺ–≥",
    other: "–ĺ–Ļ—Ä–ĺ–Ľ—Ü–ĺ–ĺ–≥–ĺ–ĺ—Ä {{count}} –ī–ĺ–Ľ–ĺ–ĺ —Ö–ĺ–Ĺ–ĺ–≥",
  },

  xWeeks: {
    one: "1 –ī–ĺ–Ľ–ĺ–ĺ —Ö–ĺ–Ĺ–ĺ–≥",
    other: "{{count}} –ī–ĺ–Ľ–ĺ–ĺ —Ö–ĺ–Ĺ–ĺ–≥",
  },

  aboutXMonths: {
    one: "–ĺ–Ļ—Ä–ĺ–Ľ—Ü–ĺ–ĺ–≥–ĺ–ĺ—Ä 1 —Ā–į—Ä",
    other: "–ĺ–Ļ—Ä–ĺ–Ľ—Ü–ĺ–ĺ–≥–ĺ–ĺ—Ä {{count}} —Ā–į—Ä",
  },

  xMonths: {
    one: "1 —Ā–į—Ä",
    other: "{{count}} —Ā–į—Ä",
  },

  aboutXYears: {
    one: "–ĺ–Ļ—Ä–ĺ–Ľ—Ü–ĺ–ĺ–≥–ĺ–ĺ—Ä 1 –∂–ł–Ľ",
    other: "–ĺ–Ļ—Ä–ĺ–Ľ—Ü–ĺ–ĺ–≥–ĺ–ĺ—Ä {{count}} –∂–ł–Ľ",
  },

  xYears: {
    one: "1 –∂–ł–Ľ",
    other: "{{count}} –∂–ł–Ľ",
  },

  overXYears: {
    one: "1 –∂–ł–Ľ –≥–į—Ä–į–Ĺ",
    other: "{{count}} –∂–ł–Ľ –≥–į—Ä–į–Ĺ",
  },

  almostXYears: {
    one: "–Ī–į—Ä–į–≥ 1 –∂–ł–Ľ",
    other: "–Ī–į—Ä–į–≥ {{count}} –∂–ł–Ľ",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    /**
     * Append genitive case
     */
    const words = result.split(" ");
    const lastword = words.pop();
    result = words.join(" ");
    switch (lastword) {
      case "—Ā–Ķ–ļ—É–Ĺ–ī":
        result += " —Ā–Ķ–ļ—É–Ĺ–ī–ł–Ļ–Ĺ";
        break;
      case "–ľ–ł–Ĺ—É—ā":
        result += " –ľ–ł–Ĺ—É—ā—č–Ĺ";
        break;
      case "—Ü–į–≥":
        result += " —Ü–į–≥–ł–Ļ–Ĺ";
        break;
      case "”©–ī”©—Ä":
        result += " ”©–ī—Ä–ł–Ļ–Ĺ";
        break;
      case "—Ā–į—Ä":
        result += " —Ā–į—Ä—č–Ĺ";
        break;
      case "–∂–ł–Ľ":
        result += " –∂–ł–Ľ–ł–Ļ–Ĺ";
        break;
      case "—Ö–ĺ–Ĺ–ĺ–≥":
        result += " —Ö–ĺ–Ĺ–ĺ–≥–ł–Ļ–Ĺ";
        break;
      case "–≥–į—Ä–į–Ĺ":
        result += " –≥–į—Ä–į–Ĺ—č";
        break;
      case "—Ö“Į—Ä—ć—Ö–≥“Į–Ļ":
        result += " —Ö“Į—Ä—ć—Ö–≥“Į–Ļ —Ö—É–≥–į—Ü–į–į–Ĺ—č";
        break;
      default:
        result += lastword + "-–Ĺ";
    }

    if (options.comparison && options.comparison > 0) {
      return result + " –ī–į—Ä–į–į";
    } else {
      return result + " ”©–ľ–Ĺ”©";
    }
  }

  return result;
};
