const formatRelativeLocale = {
  lastWeek: (date) => {
    const day = date.getDay();

    switch (day) {
      case 0:
        return "'–Ņ—Ä–ĺ—ą–Ľ–Ķ –Ĺ–Ķ–ī–Ķ—ô–Ķ —É' p";
      case 3:
        return "'–Ņ—Ä–ĺ—ą–Ľ–Ķ —Ā—Ä–Ķ–ī–Ķ —É' p";
      case 6:
        return "'–Ņ—Ä–ĺ—ą–Ľ–Ķ —Ā—É–Ī–ĺ—ā–Ķ —É' p";
      default:
        return "'–Ņ—Ä–ĺ—ą–Ľ–ł' EEEE '—É' p";
    }
  },
  yesterday: "'—ė—É—á–Ķ —É' p",
  today: "'–ī–į–Ĺ–į—Ā —É' p",
  tomorrow: "'—Ā—É—ā—Ä–į —É' p",
  nextWeek: (date) => {
    const day = date.getDay();

    switch (day) {
      case 0:
        return "'—Ā–Ľ–Ķ–ī–Ķ—õ–Ķ –Ĺ–Ķ–ī–Ķ—ô–Ķ —É' p";
      case 3:
        return "'—Ā–Ľ–Ķ–ī–Ķ—õ—É —Ā—Ä–Ķ–ī—É —É' p";
      case 6:
        return "'—Ā–Ľ–Ķ–ī–Ķ—õ—É —Ā—É–Ī–ĺ—ā—É —É' p";
      default:
        return "'—Ā–Ľ–Ķ–ī–Ķ—õ–ł' EEEE '—É' p";
    }
  },
  other: "P",
};

export const formatRelative = (token, date, _baseDate, _options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date);
  }

  return format;
};
