const formatRelativeLocale = {
  lastWeek: (date) => {
    switch (date.getDay()) {
      case 0:
        return "'proŇ°le nedjelje u' p";
      case 3:
        return "'proŇ°le srijede u' p";
      case 6:
        return "'proŇ°le subote u' p";
      default:
        return "'proŇ°li' EEEE 'u' p";
    }
  },
  yesterday: "'juńće u' p",
  today: "'danas u' p",
  tomorrow: "'sutra u' p",
  nextWeek: (date) => {
    switch (date.getDay()) {
      case 0:
        return "'sljedeńáe nedjelje u' p";
      case 3:
        return "'sljedeńáu srijedu u' p";
      case 6:
        return "'sljedeńáu subotu u' p";
      default:
        return "'sljedeńái' EEEE 'u' p";
    }
  },
  other: "P",
};

export const formatRelative = (token, date, _baseDate, _options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date);
  }

  return format;
};
