import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(-?[–≤—Ä–ľ—ā][–ł])?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((–Ņ—Ä)?–Ĺ\.?\s?–Ķ\.?)/i,
  abbreviated: /^((–Ņ—Ä)?–Ĺ\.?\s?–Ķ\.?)/i,
  wide: /^(–Ņ—Ä–Ķ–ī –Ĺ–į—ą–į—ā–į –Ķ—Ä–į|–Ĺ–į—ą–į—ā–į –Ķ—Ä–į)/i,
};
const parseEraPatterns = {
  any: [/^–Ņ/i, /^–Ĺ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[–≤—Ä—ā]?–ł?)? –ļ–≤.?/i,
  wide: /^[1234](-?[–≤—Ä—ā]?–ł?)? –ļ–≤–į—Ä—ā–į–Ľ/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchDayPatterns = {
  narrow: /^[–Ĺ–Ņ–≤—Ā—á]/i,
  short: /^(–Ĺ–Ķ|–Ņ–ĺ|–≤—ā|—Ā—Ä|—á–Ķ|–Ņ–Ķ|—Ā–į)/i,
  abbreviated: /^(–Ĺ–Ķ–ī|–Ņ–ĺ–Ĺ|–≤—ā–ĺ|—Ā—Ä–Ķ|—á–Ķ—ā|–Ņ–Ķ—ā|—Ā–į–Ī)/i,
  wide: /^(–Ĺ–Ķ–ī–Ķ–Ľ–į|–Ņ–ĺ–Ĺ–Ķ–ī–Ķ–Ľ–Ĺ–ł–ļ|–≤—ā–ĺ—Ä–Ĺ–ł–ļ|—Ā—Ä–Ķ–ī–į|—á–Ķ—ā–≤—Ä—ā–ĺ–ļ|–Ņ–Ķ—ā–ĺ–ļ|—Ā–į–Ī–ĺ—ā–į)/i,
};

const parseDayPatterns = {
  narrow: [/^–Ĺ/i, /^–Ņ/i, /^–≤/i, /^—Ā/i, /^—á/i, /^–Ņ/i, /^—Ā/i],
  any: [/^–Ĺ[–Ķ–ī]/i, /^–Ņ[–ĺ–Ĺ]/i, /^–≤—ā/i, /^—Ā—Ä/i, /^—á[–Ķ—ā]/i, /^–Ņ[–Ķ—ā]/i, /^—Ā[–į–Ī]/i],
};

const matchMonthPatterns = {
  abbreviated: /^(—ė–į–Ĺ|—Ą–Ķ–≤|–ľ–į—Ä|–į–Ņ—Ä|–ľ–į—ė|—ė—É–Ĺ|—ė—É–Ľ|–į–≤–≥|—Ā–Ķ–Ņ|–ĺ–ļ—ā|–Ĺ–ĺ–Ķ–ľ|–ī–Ķ–ļ)/i,
  wide: /^(—ė–į–Ĺ—É–į—Ä–ł|—Ą–Ķ–≤—Ä—É–į—Ä–ł|–ľ–į—Ä—ā|–į–Ņ—Ä–ł–Ľ|–ľ–į—ė|—ė—É–Ĺ–ł|—ė—É–Ľ–ł|–į–≤–≥—É—Ā—ā|—Ā–Ķ–Ņ—ā–Ķ–ľ–≤—Ä–ł|–ĺ–ļ—ā–ĺ–ľ–≤—Ä–ł|–Ĺ–ĺ–Ķ–ľ–≤—Ä–ł|–ī–Ķ–ļ–Ķ–ľ–≤—Ä–ł)/i,
};
const parseMonthPatterns = {
  any: [
    /^—ė–į/i,
    /^–§/i,
    /^–ľ–į—Ä/i,
    /^–į–Ņ/i,
    /^–ľ–į—ė/i,
    /^—ė—É–Ĺ/i,
    /^—ė—É–Ľ/i,
    /^–į–≤/i,
    /^—Ā–Ķ/i,
    /^–ĺ–ļ—ā/i,
    /^–Ĺ–ĺ/i,
    /^–ī–Ķ/i,
  ],
};

const matchDayPeriodPatterns = {
  any: /^(–Ņ—Ä–Ķ—ā–Ņ|–Ņ–ĺ–Ņ–Ľ|–Ņ–ĺ–Ľ–Ĺ–ĺ—ú|—É—ā—Ä–ĺ|–Ņ–Ľ–į–ī–Ĺ–Ķ|–≤–Ķ—á–Ķ—Ä|–Ĺ–ĺ—ú)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /–Ņ—Ä–Ķ—ā–Ņ–Ľ–į–ī–Ĺ–Ķ/i,
    pm: /–Ņ–ĺ–Ņ–Ľ–į–ī–Ĺ–Ķ/i,
    midnight: /–Ņ–ĺ–Ľ–Ĺ–ĺ—ú/i,
    noon: /–Ĺ–į–Ņ–Ľ–į–ī–Ĺ–Ķ/i,
    morning: /–Ĺ–į—É—ā—Ä–ĺ/i,
    afternoon: /–Ņ–ĺ–Ņ–Ľ–į–ī–Ĺ–Ķ/i,
    evening: /–Ĺ–į–≤–Ķ—á–Ķ—Ä/i,
    night: /–Ĺ–ĺ—ú–Ķ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
