import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(—á–ł)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(–ľ\.–į|–ľ\.)/i,
  abbreviated: /^(–ľ\.–į|–ľ\.)/i,
  wide: /^(–ľ–ł–Ľ–ĺ–ī–ī–į–Ĺ –į–≤–≤–į–Ľ|–ľ–ł–Ľ–ĺ–ī–ī–į–Ĺ –ļ–Ķ–Ļ–ł–Ĺ)/i,
};
const parseEraPatterns = {
  any: [/^–ľ/i, /^–į/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234]-—á–ĺ—Ä./i,
  wide: /^[1234]-—á–ĺ—Ä–į–ļ/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[—Ź—Ą–ľ–į–ľ–ł–ł–į—Ā–ĺ–Ĺ–ī]/i,
  abbreviated: /^(—Ź–Ĺ–≤|—Ą–Ķ–≤|–ľ–į—Ä|–į–Ņ—Ä|–ľ–į–Ļ|–ł—é–Ĺ|–ł—é–Ľ|–į–≤–≥|—Ā–Ķ–Ĺ|–ĺ–ļ—ā|–Ĺ–ĺ—Ź|–ī–Ķ–ļ)/i,
  wide: /^(—Ź–Ĺ–≤–į—Ä|—Ą–Ķ–≤—Ä–į–Ľ|–ľ–į—Ä—ā|–į–Ņ—Ä–Ķ–Ľ|–ľ–į–Ļ|–ł—é–Ĺ|–ł—é–Ľ|–į–≤–≥—É—Ā—ā|—Ā–Ķ–Ĺ—ā–į–Ī—Ä|–ĺ–ļ—ā–į–Ī—Ä|–Ĺ–ĺ—Ź–Ī—Ä|–ī–Ķ–ļ–į–Ī—Ä)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^—Ź/i,
    /^—Ą/i,
    /^–ľ/i,
    /^–į/i,
    /^–ľ/i,
    /^–ł/i,
    /^–ł/i,
    /^–į/i,
    /^—Ā/i,
    /^–ĺ/i,
    /^–Ĺ/i,
    /^–ī/i,
  ],

  any: [
    /^—Ź/i,
    /^—Ą/i,
    /^–ľ–į—Ä/i,
    /^–į–Ņ/i,
    /^–ľ–į–Ļ/i,
    /^–ł—é–Ĺ/i,
    /^–ł—é–Ľ/i,
    /^–į–≤/i,
    /^—Ā/i,
    /^–ĺ/i,
    /^–Ĺ/i,
    /^–ī/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[—Ź–ī—Ā—á–Ņ–∂—ą]/i,
  short: /^(—Ź–ļ|–ī—É|—Ā–Ķ|—á–ĺ|–Ņ–į|–∂—É|—ą–į)/i,
  abbreviated: /^(—Ź–ļ—ą|–ī—É—ą|—Ā–Ķ—ą|—á–ĺ—Ä|–Ņ–į–Ļ|–∂—É–ľ|—ą–į–Ĺ)/i,
  wide: /^(—Ź–ļ—ą–į–Ĺ–Ī–į|–ī—É—ą–į–Ĺ–Ī–į|—Ā–Ķ—ą–į–Ĺ–Ī–į|—á–ĺ—Ä—ą–į–Ĺ–Ī–į|–Ņ–į–Ļ—ą–į–Ĺ–Ī–į|–∂—É–ľ–į|—ą–į–Ĺ–Ī–į)/i,
};
const parseDayPatterns = {
  narrow: [/^—Ź/i, /^–ī/i, /^—Ā/i, /^—á/i, /^–Ņ/i, /^–∂/i, /^—ą/i],
  any: [/^—Ź–ļ/i, /^–ī—É/i, /^—Ā–Ķ/i, /^—á–ĺ—Ä/i, /^–Ņ–į–Ļ/i, /^–∂—É/i, /^—ą–į–Ĺ/i],
};

const matchDayPeriodPatterns = {
  any: /^(–Ņ\.–ĺ\.|–Ņ\.–ļ\.|—Ź—Ä–ł–ľ —ā—É–Ĺ|–Ņ–Ķ—ą–ł–Ĺ–ī–į–Ĺ –ļ–Ķ–Ļ–ł–Ĺ|(—ć—Ä—ā–į–Ľ–į–Ī|–Ņ–Ķ—ą–ł–Ĺ–ī–į–Ĺ –ļ–Ķ–Ļ–ł–Ĺ|–ļ–Ķ—á–į—Ā–ł|—ā—É–Ĺ))/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^–Ņ\.–ĺ\./i,
    pm: /^–Ņ\.–ļ\./i,
    midnight: /^—Ź—Ä–ł–ľ —ā—É–Ĺ/i,
    noon: /^–Ņ–Ķ—ą–ł–Ĺ–ī–į–Ĺ –ļ–Ķ–Ļ–ł–Ĺ/i,
    morning: /—ć—Ä—ā–į–Ľ–į–Ī/i,
    afternoon: /–Ņ–Ķ—ą–ł–Ĺ–ī–į–Ĺ –ļ–Ķ–Ļ–ł–Ĺ/i,
    evening: /–ļ–Ķ—á–į—Ā–ł/i,
    night: /—ā—É–Ĺ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
