const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "–Ņ–ĺ–ľ–į–Ľ–ļ—É –ĺ–ī —Ā–Ķ–ļ—É–Ĺ–ī–į",
    other: "–Ņ–ĺ–ľ–į–Ľ–ļ—É –ĺ–ī {{count}} —Ā–Ķ–ļ—É–Ĺ–ī–ł",
  },

  xSeconds: {
    one: "1 —Ā–Ķ–ļ—É–Ĺ–ī–į",
    other: "{{count}} —Ā–Ķ–ļ—É–Ĺ–ī–ł",
  },

  halfAMinute: "–Ņ–ĺ–Ľ–ĺ–≤–ł–Ĺ–į –ľ–ł–Ĺ—É—ā–į",

  lessThanXMinutes: {
    one: "–Ņ–ĺ–ľ–į–Ľ–ļ—É –ĺ–ī –ľ–ł–Ĺ—É—ā–į",
    other: "–Ņ–ĺ–ľ–į–Ľ–ļ—É –ĺ–ī {{count}} –ľ–ł–Ĺ—É—ā–ł",
  },

  xMinutes: {
    one: "1 –ľ–ł–Ĺ—É—ā–į",
    other: "{{count}} –ľ–ł–Ĺ—É—ā–ł",
  },

  aboutXHours: {
    one: "–ĺ–ļ–ĺ–Ľ—É 1 —á–į—Ā",
    other: "–ĺ–ļ–ĺ–Ľ—É {{count}} —á–į—Ā–į",
  },

  xHours: {
    one: "1 —á–į—Ā",
    other: "{{count}} —á–į—Ā–į",
  },

  xDays: {
    one: "1 –ī–Ķ–Ĺ",
    other: "{{count}} –ī–Ķ–Ĺ–į",
  },

  aboutXWeeks: {
    one: "–ĺ–ļ–ĺ–Ľ—É 1 –Ĺ–Ķ–ī–Ķ–Ľ–į",
    other: "–ĺ–ļ–ĺ–Ľ—É {{count}} –ľ–Ķ—Ā–Ķ—Ü–ł",
  },

  xWeeks: {
    one: "1 –Ĺ–Ķ–ī–Ķ–Ľ–į",
    other: "{{count}} –Ĺ–Ķ–ī–Ķ–Ľ–ł",
  },

  aboutXMonths: {
    one: "–ĺ–ļ–ĺ–Ľ—É 1 –ľ–Ķ—Ā–Ķ—Ü",
    other: "–ĺ–ļ–ĺ–Ľ—É {{count}} –Ĺ–Ķ–ī–Ķ–Ľ–ł",
  },

  xMonths: {
    one: "1 –ľ–Ķ—Ā–Ķ—Ü",
    other: "{{count}} –ľ–Ķ—Ā–Ķ—Ü–ł",
  },

  aboutXYears: {
    one: "–ĺ–ļ–ĺ–Ľ—É 1 –≥–ĺ–ī–ł–Ĺ–į",
    other: "–ĺ–ļ–ĺ–Ľ—É {{count}} –≥–ĺ–ī–ł–Ĺ–ł",
  },

  xYears: {
    one: "1 –≥–ĺ–ī–ł–Ĺ–į",
    other: "{{count}} –≥–ĺ–ī–ł–Ĺ–ł",
  },

  overXYears: {
    one: "–Ņ–ĺ–≤–Ķ—ú–Ķ –ĺ–ī 1 –≥–ĺ–ī–ł–Ĺ–į",
    other: "–Ņ–ĺ–≤–Ķ—ú–Ķ –ĺ–ī {{count}} –≥–ĺ–ī–ł–Ĺ–ł",
  },

  almostXYears: {
    one: "–Ī–Ķ–∑–ľ–į–Ľ–ļ—É 1 –≥–ĺ–ī–ł–Ĺ–į",
    other: "–Ī–Ķ–∑–ľ–į–Ľ–ļ—É {{count}} –≥–ĺ–ī–ł–Ĺ–ł",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return "–∑–į " + result;
    } else {
      return "–Ņ—Ä–Ķ–ī " + result;
    }
  }

  return result;
};
