import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(-?(–Ķ|–Ļ|—Ē|–į|—Ź))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((–ī–ĺ )?–Ĺ\.?\s?–Ķ\.?)/i,
  abbreviated: /^((–ī–ĺ )?–Ĺ\.?\s?–Ķ\.?)/i,
  wide: /^(–ī–ĺ –Ĺ–į—ą–ĺ—ó –Ķ—Ä–ł|–Ĺ–į—ą–ĺ—ó –Ķ—Ä–ł|–Ĺ–į—ą–į –Ķ—Ä–į)/i,
};

const parseEraPatterns = {
  any: [/^–ī/i, /^–Ĺ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[–ł—Ė]?–Ļ?)? –ļ–≤.?/i,
  wide: /^[1234](-?[–ł—Ė]?–Ļ?)? –ļ–≤–į—Ä—ā–į–Ľ/i,
};

const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[—Ā–Ľ–Ī–ļ—ā—á–≤–∂–≥]/i,
  abbreviated:
    /^(—Ā—Ė—á|–Ľ—é—ā|–Ī–Ķ—Ä(–Ķ–∑)?|–ļ–≤—Ė—ā|—ā—Ä–į–≤|—á–Ķ—Ä–≤|–Ľ–ł–Ņ|—Ā–Ķ—Ä–Ņ|–≤–Ķ—Ä(–Ķ—Ā)?|–∂–ĺ–≤—ā|–Ľ–ł—Ā(—ā–ĺ–Ņ)?|–≥—Ä—É–ī)\.?/i,
  wide: /^(—Ā—Ė—á–Ķ–Ĺ—Ć|—Ā—Ė—á–Ĺ—Ź|–Ľ—é—ā–ł–Ļ|–Ľ—é—ā–ĺ–≥–ĺ|–Ī–Ķ—Ä–Ķ–∑–Ķ–Ĺ—Ć|–Ī–Ķ—Ä–Ķ–∑–Ĺ—Ź|–ļ–≤—Ė—ā–Ķ–Ĺ—Ć|–ļ–≤—Ė—ā–Ĺ—Ź|—ā—Ä–į–≤–Ķ–Ĺ—Ć|—ā—Ä–į–≤–Ĺ—Ź|—á–Ķ—Ä–≤–Ĺ—Ź|—á–Ķ—Ä–≤–Ķ–Ĺ—Ć|–Ľ–ł–Ņ–Ķ–Ĺ—Ć|–Ľ–ł–Ņ–Ĺ—Ź|—Ā–Ķ—Ä–Ņ–Ķ–Ĺ—Ć|—Ā–Ķ—Ä–Ņ–Ĺ—Ź|–≤–Ķ—Ä–Ķ—Ā–Ķ–Ĺ—Ć|–≤–Ķ—Ä–Ķ—Ā–Ĺ—Ź|–∂–ĺ–≤—ā–Ķ–Ĺ—Ć|–∂–ĺ–≤—ā–Ĺ—Ź|–Ľ–ł—Ā—ā–ĺ–Ņ–į–ī[–į]?|–≥—Ä—É–ī–Ķ–Ĺ—Ć|–≥—Ä—É–ī–Ĺ—Ź)/i,
};

const parseMonthPatterns = {
  narrow: [
    /^—Ā/i,
    /^–Ľ/i,
    /^–Ī/i,
    /^–ļ/i,
    /^—ā/i,
    /^—á/i,
    /^–Ľ/i,
    /^—Ā/i,
    /^–≤/i,
    /^–∂/i,
    /^–Ľ/i,
    /^–≥/i,
  ],

  any: [
    /^—Ā—Ė/i,
    /^–Ľ—é/i,
    /^–Ī/i,
    /^–ļ/i,
    /^—ā/i,
    /^—á/i,
    /^–Ľ–ł–Ņ/i,
    /^—Ā–Ķ/i,
    /^–≤/i,
    /^–∂/i,
    /^–Ľ–ł—Ā/i,
    /^–≥/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[–Ĺ–Ņ–≤—Ā—á]/i,
  short: /^(–Ĺ–ī|–Ņ–Ĺ|–≤—ā|—Ā—Ä|—á—ā|–Ņ—ā|—Ā–Ī)\.?/i,
  abbreviated: /^(–Ĺ–Ķ–ī|–Ņ–ĺ–Ĺ|–≤—Ė–≤|—Ā–Ķ—Ä|—á–Ķ?—ā–≤|–Ņ—ā–Ĺ?|—Ā—É–Ī)\.?/i,
  wide: /^(–Ĺ–Ķ–ī—Ė–Ľ[—Ź—Ė]|–Ņ–ĺ–Ĺ–Ķ–ī—Ė–Ľ[–ĺ–ļ][–ļ–į]|–≤—Ė–≤—ā–ĺ—Ä[–ĺ–ļ][–ļ–į]|—Ā–Ķ—Ä–Ķ–ī[–į–ł]|—á–Ķ—ā–≤–Ķ—Ä(–≥–į)?|–Ņ\W*?—Ź—ā–Ĺ–ł—Ü[—Ź—Ė]|—Ā—É–Ī–ĺ—ā[–į–ł])/i,
};

const parseDayPatterns = {
  narrow: [/^–Ĺ/i, /^–Ņ/i, /^–≤/i, /^—Ā/i, /^—á/i, /^–Ņ/i, /^—Ā/i],
  any: [/^–Ĺ/i, /^–Ņ[–ĺ–Ĺ]/i, /^–≤/i, /^—Ā[–Ķ—Ä]/i, /^—á/i, /^–Ņ\W*?[—Ź—ā]/i, /^—Ā[—É–Ī]/i],
};

const matchDayPeriodPatterns = {
  narrow: /^([–ī–Ņ]–Ņ|–Ņ—Ė–≤–Ĺ\.?|–Ņ–ĺ–Ľ\.?|—Ä–į–Ĺ–ĺ–ļ|—Ä–į–Ĺ–ļ—É|–ī–Ķ–Ĺ—Ć|–ī–Ĺ—Ź|–≤–Ķ—á\.?|–Ĺ—Ė—á|–Ĺ–ĺ—á—Ė)/i,
  abbreviated: /^([–ī–Ņ]–Ņ|–Ņ—Ė–≤–Ĺ\.?|–Ņ–ĺ–Ľ\.?|—Ä–į–Ĺ–ĺ–ļ|—Ä–į–Ĺ–ļ—É|–ī–Ķ–Ĺ—Ć|–ī–Ĺ—Ź|–≤–Ķ—á\.?|–Ĺ—Ė—á|–Ĺ–ĺ—á—Ė)/i,
  wide: /^([–ī–Ņ]–Ņ|–Ņ—Ė–≤–Ĺ—Ė—á|–Ņ–ĺ–Ľ—É–ī–Ķ–Ĺ—Ć|—Ä–į–Ĺ–ĺ–ļ|—Ä–į–Ĺ–ļ—É|–ī–Ķ–Ĺ—Ć|–ī–Ĺ—Ź|–≤–Ķ—á—Ė—Ä|–≤–Ķ—á–ĺ—Ä–į|–Ĺ—Ė—á|–Ĺ–ĺ—á—Ė)/i,
};

const parseDayPeriodPatterns = {
  any: {
    am: /^–ī–Ņ/i,
    pm: /^–Ņ–Ņ/i,
    midnight: /^–Ņ—Ė–≤–Ĺ/i,
    noon: /^–Ņ–ĺ–Ľ/i,
    morning: /^—Ä/i,
    afternoon: /^–ī[–Ķ–Ĺ]/i,
    evening: /^–≤/i,
    night: /^–Ĺ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
