import { isSameWeek } from "../../../isSameWeek.js";

const accusativeWeekdays = [
  "–≤–ĺ—Ā–ļ—Ä–Ķ—Ā–Ķ–Ĺ—Ć–Ķ",
  "–Ņ–ĺ–Ĺ–Ķ–ī–Ķ–Ľ—Ć–Ĺ–ł–ļ",
  "–≤—ā–ĺ—Ä–Ĺ–ł–ļ",
  "—Ā—Ä–Ķ–ī—É",
  "—á–Ķ—ā–≤–Ķ—Ä–≥",
  "–Ņ—Ź—ā–Ĺ–ł—Ü—É",
  "—Ā—É–Ī–Ī–ĺ—ā—É",
];

function lastWeek(day) {
  const weekday = accusativeWeekdays[day];

  switch (day) {
    case 0:
      return "'–≤ –Ņ—Ä–ĺ—ą–Ľ–ĺ–Ķ " + weekday + " –≤' p";
    case 1:
    case 2:
    case 4:
      return "'–≤ –Ņ—Ä–ĺ—ą–Ľ—č–Ļ " + weekday + " –≤' p";
    case 3:
    case 5:
    case 6:
      return "'–≤ –Ņ—Ä–ĺ—ą–Ľ—É—é " + weekday + " –≤' p";
  }
}

function thisWeek(day) {
  const weekday = accusativeWeekdays[day];

  if (day === 2 /* Tue */) {
    return "'–≤–ĺ " + weekday + " –≤' p";
  } else {
    return "'–≤ " + weekday + " –≤' p";
  }
}

function nextWeek(day) {
  const weekday = accusativeWeekdays[day];

  switch (day) {
    case 0:
      return "'–≤ —Ā–Ľ–Ķ–ī—É—é—Č–Ķ–Ķ " + weekday + " –≤' p";
    case 1:
    case 2:
    case 4:
      return "'–≤ —Ā–Ľ–Ķ–ī—É—é—Č–ł–Ļ " + weekday + " –≤' p";
    case 3:
    case 5:
    case 6:
      return "'–≤ —Ā–Ľ–Ķ–ī—É—é—Č—É—é " + weekday + " –≤' p";
  }
}

const formatRelativeLocale = {
  lastWeek: (date, baseDate, options) => {
    const day = date.getDay();
    if (isSameWeek(date, baseDate, options)) {
      return thisWeek(day);
    } else {
      return lastWeek(day);
    }
  },
  yesterday: "'–≤—á–Ķ—Ä–į –≤' p",
  today: "'—Ā–Ķ–≥–ĺ–ī–Ĺ—Ź –≤' p",
  tomorrow: "'–∑–į–≤—ā—Ä–į –≤' p",
  nextWeek: (date, baseDate, options) => {
    const day = date.getDay();
    if (isSameWeek(date, baseDate, options)) {
      return thisWeek(day);
    } else {
      return nextWeek(day);
    }
  },
  other: "P",
};

export const formatRelative = (token, date, baseDate, options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date, baseDate, options);
  }

  return format;
};
