import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(-?(–Ķ|—Ź|–Ļ|–ĺ–Ķ|—Ć–Ķ|–į—Ź|—Ć—Ź|—č–Ļ|–ĺ–Ļ|–ł–Ļ|—č–Ļ))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((–ī–ĺ )?–Ĺ\.?\s?—ć\.?)/i,
  abbreviated: /^((–ī–ĺ )?–Ĺ\.?\s?—ć\.?)/i,
  wide: /^(–ī–ĺ –Ĺ–į—ą–Ķ–Ļ —ć—Ä—č|–Ĺ–į—ą–Ķ–Ļ —ć—Ä—č|–Ĺ–į—ą–į —ć—Ä–į)/i,
};
const parseEraPatterns = {
  any: [/^–ī/i, /^–Ĺ/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[—č–ĺ–ł]?–Ļ?)? –ļ–≤.?/i,
  wide: /^[1234](-?[—č–ĺ–ł]?–Ļ?)? –ļ–≤–į—Ä—ā–į–Ľ/i,
};

const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[—Ź—Ą–ľ–į–ł—Ā–ĺ–Ĺ–ī]/i,
  abbreviated:
    /^(—Ź–Ĺ–≤|—Ą–Ķ–≤|–ľ–į—Ä—ā?|–į–Ņ—Ä|–ľ–į[–Ļ—Ź]|–ł—é–Ĺ[—Ć—Ź]?|–ł—é–Ľ[—Ć—Ź]?|–į–≤–≥|—Ā–Ķ–Ĺ—ā?|–ĺ–ļ—ā|–Ĺ–ĺ—Ź–Ī?|–ī–Ķ–ļ)\.?/i,
  wide: /^(—Ź–Ĺ–≤–į—Ä[—Ć—Ź]|—Ą–Ķ–≤—Ä–į–Ľ[—Ć—Ź]|–ľ–į—Ä—ā–į?|–į–Ņ—Ä–Ķ–Ľ[—Ć—Ź]|–ľ–į[–Ļ—Ź]|–ł—é–Ĺ[—Ć—Ź]|–ł—é–Ľ[—Ć—Ź]|–į–≤–≥—É—Ā—ā–į?|—Ā–Ķ–Ĺ—ā—Ź–Ī—Ä[—Ć—Ź]|–ĺ–ļ—ā—Ź–Ī—Ä[—Ć—Ź]|–ĺ–ļ—ā—Ź–Ī—Ä[—Ć—Ź]|–Ĺ–ĺ—Ź–Ī—Ä[—Ć—Ź]|–ī–Ķ–ļ–į–Ī—Ä[—Ć—Ź])/i,
};

const parseMonthPatterns = {
  narrow: [
    /^—Ź/i,
    /^—Ą/i,
    /^–ľ/i,
    /^–į/i,
    /^–ľ/i,
    /^–ł/i,
    /^–ł/i,
    /^–į/i,
    /^—Ā/i,
    /^–ĺ/i,
    /^–Ĺ/i,
    /^—Ź/i,
  ],

  any: [
    /^—Ź/i,
    /^—Ą/i,
    /^–ľ–į—Ä/i,
    /^–į–Ņ/i,
    /^–ľ–į[–Ļ—Ź]/i,
    /^–ł—é–Ĺ/i,
    /^–ł—é–Ľ/i,
    /^–į–≤/i,
    /^—Ā/i,
    /^–ĺ/i,
    /^–Ĺ/i,
    /^–ī/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[–≤–Ņ—Ā—á]/i,
  short: /^(–≤—Ā|–≤–ĺ|–Ņ–Ĺ|–Ņ–ĺ|–≤—ā|—Ā—Ä|—á—ā|—á–Ķ|–Ņ—ā|–Ņ—Ź|—Ā–Ī|—Ā—É)\.?/i,
  abbreviated: /^(–≤—Ā–ļ|–≤–ĺ—Ā|–Ņ–Ĺ–ī|–Ņ–ĺ–Ĺ|–≤—ā—Ä|–≤—ā–ĺ|—Ā—Ä–ī|—Ā—Ä–Ķ|—á—ā–≤|—á–Ķ—ā|–Ņ—ā–Ĺ|–Ņ—Ź—ā|—Ā—É–Ī).?/i,
  wide: /^(–≤–ĺ—Ā–ļ—Ä–Ķ—Ā–Ķ–Ĺ—Ć[–Ķ—Ź]|–Ņ–ĺ–Ĺ–Ķ–ī–Ķ–Ľ—Ć–Ĺ–ł–ļ–į?|–≤—ā–ĺ—Ä–Ĺ–ł–ļ–į?|—Ā—Ä–Ķ–ī[–į—č]|—á–Ķ—ā–≤–Ķ—Ä–≥–į?|–Ņ—Ź—ā–Ĺ–ł—Ü[–į—č]|—Ā—É–Ī–Ī–ĺ—ā[–į—č])/i,
};

const parseDayPatterns = {
  narrow: [/^–≤/i, /^–Ņ/i, /^–≤/i, /^—Ā/i, /^—á/i, /^–Ņ/i, /^—Ā/i],
  any: [/^–≤[–ĺ—Ā]/i, /^–Ņ[–ĺ–Ĺ]/i, /^–≤/i, /^—Ā—Ä/i, /^—á/i, /^–Ņ[—Ź—ā]/i, /^—Ā[—É–Ī]/i],
};

const matchDayPeriodPatterns = {
  narrow: /^([–ī–Ņ]–Ņ|–Ņ–ĺ–Ľ–Ĺ\.?|–Ņ–ĺ–Ľ–ī\.?|—É—ā—Ä[–ĺ–į]|–ī–Ķ–Ĺ—Ć|–ī–Ĺ—Ź|–≤–Ķ—á\.?|–Ĺ–ĺ—á[—Ć–ł])/i,
  abbreviated: /^([–ī–Ņ]–Ņ|–Ņ–ĺ–Ľ–Ĺ\.?|–Ņ–ĺ–Ľ–ī\.?|—É—ā—Ä[–ĺ–į]|–ī–Ķ–Ĺ—Ć|–ī–Ĺ—Ź|–≤–Ķ—á\.?|–Ĺ–ĺ—á[—Ć–ł])/i,
  wide: /^([–ī–Ņ]–Ņ|–Ņ–ĺ–Ľ–Ĺ–ĺ—á—Ć|–Ņ–ĺ–Ľ–ī–Ķ–Ĺ—Ć|—É—ā—Ä[–ĺ–į]|–ī–Ķ–Ĺ—Ć|–ī–Ĺ—Ź|–≤–Ķ—á–Ķ—Ä–į?|–Ĺ–ĺ—á[—Ć–ł])/i,
};

const parseDayPeriodPatterns = {
  any: {
    am: /^–ī–Ņ/i,
    pm: /^–Ņ–Ņ/i,
    midnight: /^–Ņ–ĺ–Ľ–Ĺ/i,
    noon: /^–Ņ–ĺ–Ľ–ī/i,
    morning: /^—É/i,
    afternoon: /^–ī[–Ķ–Ĺ]/i,
    evening: /^–≤/i,
    night: /^–Ĺ/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
