import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern =
  /^(\d+|(◊®◊ź◊©◊ē◊ü|◊©◊†◊ô|◊©◊ú◊ô◊©◊ô|◊®◊Ď◊ô◊Ę◊ô|◊ó◊ě◊ô◊©◊ô|◊©◊ô◊©◊ô|◊©◊Ď◊ô◊Ę◊ô|◊©◊ě◊ô◊†◊ô|◊™◊©◊ô◊Ę◊ô|◊Ę◊©◊ô◊®◊ô|◊®◊ź◊©◊ē◊†◊Ē|◊©◊†◊ô◊ô◊Ē|◊©◊ú◊ô◊©◊ô◊™|◊®◊Ď◊ô◊Ę◊ô◊™|◊ó◊ě◊ô◊©◊ô◊™|◊©◊ô◊©◊ô◊™|◊©◊Ď◊ô◊Ę◊ô◊™|◊©◊ě◊ô◊†◊ô◊™|◊™◊©◊ô◊Ę◊ô◊™|◊Ę◊©◊ô◊®◊ô◊™))/i;
const parseOrdinalNumberPattern = /^(\d+|◊®◊ź|◊©◊†|◊©◊ú|◊®◊Ď|◊ó|◊©◊ô|◊©◊Ď|◊©◊ě|◊™|◊Ę)/i;

const matchEraPatterns = {
  narrow: /^◊ú(◊°◊§◊ô◊®◊Ē|◊§◊†◊Ē◊ī◊°)/i,
  abbreviated: /^◊ú(◊°◊§◊ô◊®◊Ē|◊§◊†◊Ē◊ī◊°)/i,
  wide: /^◊ú(◊§◊†◊ô ◊Ē)?◊°◊§◊ô◊®◊Ē/i,
};
const parseEraPatterns = {
  any: [/^◊ú◊§/i, /^◊ú◊°/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^q[1234]/i,
  wide: /^◊®◊Ď◊Ę◊ē◊ü [1234]/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^\d+/i,
  abbreviated: /^(◊ô◊†◊ē|◊§◊Ď◊®|◊ě◊®◊•|◊ź◊§◊®|◊ě◊ź◊ô|◊ô◊ē◊†◊ô|◊ô◊ē◊ú◊ô|◊ź◊ē◊í|◊°◊§◊ė|◊ź◊ē◊ß|◊†◊ē◊Ď|◊ď◊¶◊ě)◊≥?/i,
  wide: /^(◊ô◊†◊ē◊ź◊®|◊§◊Ď◊®◊ē◊ź◊®|◊ě◊®◊•|◊ź◊§◊®◊ô◊ú|◊ě◊ź◊ô|◊ô◊ē◊†◊ô|◊ô◊ē◊ú◊ô|◊ź◊ē◊í◊ē◊°◊ė|◊°◊§◊ė◊ě◊Ď◊®|◊ź◊ē◊ß◊ė◊ē◊Ď◊®|◊†◊ē◊Ď◊ě◊Ď◊®|◊ď◊¶◊ě◊Ď◊®)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^1$/i,
    /^2/i,
    /^3/i,
    /^4/i,
    /^5/i,
    /^6/i,
    /^7/i,
    /^8/i,
    /^9/i,
    /^10/i,
    /^11/i,
    /^12/i,
  ],

  any: [
    /^◊ô◊†/i,
    /^◊§/i,
    /^◊ě◊®/i,
    /^◊ź◊§/i,
    /^◊ě◊ź/i,
    /^◊ô◊ē◊†/i,
    /^◊ô◊ē◊ú/i,
    /^◊ź◊ē◊í/i,
    /^◊°/i,
    /^◊ź◊ē◊ß/i,
    /^◊†/i,
    /^◊ď/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[◊ź◊Ď◊í◊ď◊Ē◊ē◊©]◊≥/i,
  short: /^[◊ź◊Ď◊í◊ď◊Ē◊ē◊©]◊≥/i,
  abbreviated: /^(◊©◊Ď◊™|◊ô◊ē◊Ě (◊ź|◊Ď|◊í|◊ď|◊Ē|◊ē)◊≥)/i,
  wide: /^◊ô◊ē◊Ě (◊®◊ź◊©◊ē◊ü|◊©◊†◊ô|◊©◊ú◊ô◊©◊ô|◊®◊Ď◊ô◊Ę◊ô|◊ó◊ě◊ô◊©◊ô|◊©◊ô◊©◊ô|◊©◊Ď◊™)/i,
};
const parseDayPatterns = {
  abbreviated: [/◊ź◊≥$/i, /◊Ď◊≥$/i, /◊í◊≥$/i, /◊ď◊≥$/i, /◊Ē◊≥$/i, /◊ē◊≥$/i, /^◊©/i],
  wide: [/◊ü$/i, /◊†◊ô$/i, /◊ú◊ô◊©◊ô$/i, /◊Ę◊ô$/i, /◊ě◊ô◊©◊ô$/i, /◊©◊ô◊©◊ô$/i, /◊™$/i],
  any: [/^◊ź/i, /^◊Ď/i, /^◊í/i, /^◊ď/i, /^◊Ē/i, /^◊ē/i, /^◊©/i],
};

const matchDayPeriodPatterns = {
  any: /^(◊ź◊ó◊® ◊Ē|◊Ď)?(◊ó◊¶◊ē◊™|◊¶◊Ē◊®◊ô◊ô◊Ě|◊Ď◊ē◊ß◊®|◊Ę◊®◊Ď|◊ú◊ô◊ú◊Ē|◊ź◊ó◊Ē◊ī◊¶|◊ú◊§◊†◊Ē◊ī◊¶)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^◊ú◊§/i,
    pm: /^◊ź◊ó◊Ē/i,
    midnight: /^◊ó/i,
    noon: /^◊¶/i,
    morning: /◊Ď◊ē◊ß◊®/i,
    afternoon: /◊Ď◊¶|◊ź◊ó◊®/i,
    evening: /◊Ę◊®◊Ď/i,
    night: /◊ú◊ô◊ú◊Ē/i,
  },
};

const ordinalName = ["◊®◊ź", "◊©◊†", "◊©◊ú", "◊®◊Ď", "◊ó", "◊©◊ô", "◊©◊Ď", "◊©◊ě", "◊™", "◊Ę"];

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => {
      const number = parseInt(value, 10);
      return isNaN(number) ? ordinalName.indexOf(value) + 1 : number;
    },
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
