import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(\.)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(m√∂|ms)/i,
  abbreviated: /^(m√∂|ms)/i,
  wide: /^(milattan √∂nce|milattan sonra)/i,
};
const parseEraPatterns = {
  any: [/(^m√∂|^milattan √∂nce)/i, /(^ms|^milattan sonra)/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234]√ß/i,
  wide: /^((i|ńį)lk|(i|ńį)kinci|√ľ√ß√ľnc√ľ|son) √ßeyrek/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
  abbreviated: [/1√ß/i, /2√ß/i, /3√ß/i, /4√ß/i],
  wide: [
    /^(i|ńį)lk √ßeyrek/i,
    /(i|ńį)kinci √ßeyrek/i,
    /√ľ√ß√ľnc√ľ √ßeyrek/i,
    /son √ßeyrek/i,
  ],
};

const matchMonthPatterns = {
  narrow: /^[oŇümnhtaek]/i,
  abbreviated: /^(oca|Ňüub|mar|nis|may|haz|tem|ańüu|eyl|eki|kas|ara)/i,
  wide: /^(ocak|Ňüubat|mart|nisan|mayńĪs|haziran|temmuz|ańüustos|eyl√ľl|ekim|kasńĪm|aralńĪk)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^o/i,
    /^Ňü/i,
    /^m/i,
    /^n/i,
    /^m/i,
    /^h/i,
    /^t/i,
    /^a/i,
    /^e/i,
    /^e/i,
    /^k/i,
    /^a/i,
  ],

  any: [
    /^o/i,
    /^Ňü/i,
    /^mar/i,
    /^n/i,
    /^may/i,
    /^h/i,
    /^t/i,
    /^ańü/i,
    /^ey/i,
    /^ek/i,
    /^k/i,
    /^ar/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[ps√ßc]/i,
  short: /^(pz|pt|sa|√ßa|pe|cu|ct)/i,
  abbreviated: /^(paz|pzt|sal|√ßar|per|cum|cts)/i,
  wide: /^(pazar(?!tesi)|pazartesi|salńĪ|√ßarŇüamba|perŇüembe|cuma(?!rtesi)|cumartesi)/i,
};
const parseDayPatterns = {
  narrow: [/^p/i, /^p/i, /^s/i, /^√ß/i, /^p/i, /^c/i, /^c/i],
  any: [/^pz/i, /^pt/i, /^sa/i, /^√ßa/i, /^pe/i, /^cu/i, /^ct/i],
  wide: [
    /^pazar(?!tesi)/i,
    /^pazartesi/i,
    /^salńĪ/i,
    /^√ßarŇüamba/i,
    /^perŇüembe/i,
    /^cuma(?!rtesi)/i,
    /^cumartesi/i,
  ],
};

const matchDayPeriodPatterns = {
  narrow: /^(√∂√∂|√∂s|gy|√∂|sa|√∂s|ak|ge)/i,
  any: /^(√∂\.?\s?[√∂s]\.?|√∂ńüleden sonra|gece yarńĪsńĪ|√∂ńüle|(sabah|√∂ńü|akŇüam|gece)(leyin))/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^√∂\.?√∂\.?/i,
    pm: /^√∂\.?s\.?/i,
    midnight: /^(gy|gece yarńĪsńĪ)/i,
    noon: /^√∂ńü/i,
    morning: /^sa/i,
    afternoon: /^√∂ńüleden sonra/i,
    evening: /^ak/i,
    night: /^ge/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: function (value) {
      return parseInt(value, 10);
    },
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
