import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /\d+/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(–Ĺ—ā”©|–Ĺ—ā)/i,
  abbreviated: /^(–Ĺ—ā”©|–Ĺ—ā)/i,
  wide: /^(–Ĺ–ł–Ļ—ā–ł–Ļ–Ĺ —ā–ĺ–ĺ–Ľ–Ľ—č–Ĺ ”©–ľ–Ĺ”©|–Ĺ–ł–Ļ—ā–ł–Ļ–Ĺ —ā–ĺ–ĺ–Ľ–Ľ—č–Ĺ)/i,
};
const parseEraPatterns = {
  any: [/^(–Ĺ—ā”©|–Ĺ–ł–Ļ—ā–ł–Ļ–Ĺ —ā–ĺ–ĺ–Ľ–Ľ—č–Ĺ ”©–ľ–Ĺ”©)/i, /^(–Ĺ—ā|–Ĺ–ł–Ļ—ā–ł–Ļ–Ĺ —ā–ĺ–ĺ–Ľ–Ľ—č–Ĺ)/i],
};

const matchQuarterPatterns = {
  narrow: /^(iv|iii|ii|i)/i,
  abbreviated: /^(iv|iii|ii|i) —É–Ľ–ł—Ä–į–Ľ/i,
  wide: /^[1-4]-—Ä —É–Ľ–ł—Ä–į–Ľ/i,
};
const parseQuarterPatterns = {
  any: [/^(i(\s|$)|1)/i, /^(ii(\s|$)|2)/i, /^(iii(\s|$)|3)/i, /^(iv(\s|$)|4)/i],
};

const matchMonthPatterns = {
  narrow: /^(xii|xi|x|ix|viii|vii|vi|v|iv|iii|ii|i)/i,
  abbreviated:
    /^(1-—Ä —Ā–į—Ä|2-—Ä —Ā–į—Ä|3-—Ä —Ā–į—Ä|4-—Ä —Ā–į—Ä|5-—Ä —Ā–į—Ä|6-—Ä —Ā–į—Ä|7-—Ä —Ā–į—Ä|8-—Ä —Ā–į—Ä|9-—Ä —Ā–į—Ä|10-—Ä —Ā–į—Ä|11-—Ä —Ā–į—Ä|12-—Ä —Ā–į—Ä)/i,
  wide: /^(–Ĺ—ć–≥–ī“Į–≥—ć—ć—Ä —Ā–į—Ä|—Ö–ĺ—Ď—Ä–ī—É–≥–į–į—Ä —Ā–į—Ä|–≥—É—Ä–į–≤–ī—É–≥–į–į—Ä —Ā–į—Ä|–ī”©—Ä”©–≤–ī“Į–≥—ć—ć—Ä —Ā–į—Ä|—ā–į–≤–ī—É–≥–į–į—Ä —Ā–į—Ä|–∑—É—Ä–≥–į–į–ī—É–≥–į–į—Ä —Ā–į—Ä|–ī–ĺ–Ľ–ĺ–ĺ–ī—É–≥–į–į—Ä —Ā–į—Ä|–Ĺ–į–Ļ–ľ–ī—É–≥–į–į—Ä —Ā–į—Ä|–Ķ—Ā–ī“Į–≥—ć—ć—Ä —Ā–į—Ä|–į—Ä–į–≤–ī—É–≥–į–į—Ä —Ā–į—Ä|–į—Ä–≤–į–Ĺ –Ĺ—ć–≥–ī“Į–≥—ć—ć—Ä —Ā–į—Ä|–į—Ä–≤–į–Ĺ —Ö–ĺ—Ď—Ä–ī—É–≥–į–į—Ä —Ā–į—Ä)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^i$/i,
    /^ii$/i,
    /^iii$/i,
    /^iv$/i,
    /^v$/i,
    /^vi$/i,
    /^vii$/i,
    /^viii$/i,
    /^ix$/i,
    /^x$/i,
    /^xi$/i,
    /^xii$/i,
  ],

  any: [
    /^(1|–Ĺ—ć–≥–ī“Į–≥—ć—ć—Ä)/i,
    /^(2|—Ö–ĺ—Ď—Ä–ī—É–≥–į–į—Ä)/i,
    /^(3|–≥—É—Ä–į–≤–ī—É–≥–į–į—Ä)/i,
    /^(4|–ī”©—Ä”©–≤–ī“Į–≥—ć—ć—Ä)/i,
    /^(5|—ā–į–≤–ī—É–≥–į–į—Ä)/i,
    /^(6|–∑—É—Ä–≥–į–į–ī—É–≥–į–į—Ä)/i,
    /^(7|–ī–ĺ–Ľ–ĺ–ĺ–ī—É–≥–į–į—Ä)/i,
    /^(8|–Ĺ–į–Ļ–ľ–ī—É–≥–į–į—Ä)/i,
    /^(9|–Ķ—Ā–ī“Į–≥—ć—ć—Ä)/i,
    /^(10|–į—Ä–į–≤–ī—É–≥–į–į—Ä)/i,
    /^(11|–į—Ä–≤–į–Ĺ –Ĺ—ć–≥–ī“Į–≥—ć—ć—Ä)/i,
    /^(12|–į—Ä–≤–į–Ĺ —Ö–ĺ—Ď—Ä–ī—É–≥–į–į—Ä)/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[–Ĺ–ī–ľ–Ľ–Ņ–Ī–Ī]/i,
  short: /^(–Ĺ—Ź|–ī–į|–ľ—Ź|–Ľ—Ö|–Ņ“Į|–Ī–į|–Ī—Ź)/i,
  abbreviated: /^(–Ĺ—Ź–ľ|–ī–į–≤|–ľ—Ź–≥|–Ľ—Ö–į|–Ņ“Į—Ä|–Ī–į–į|–Ī—Ź–ľ)/i,
  wide: /^(–Ĺ—Ź–ľ|–ī–į–≤–į–į|–ľ—Ź–≥–ľ–į—Ä|–Ľ—Ö–į–≥–≤–į|–Ņ“Į—Ä—ć–≤|–Ī–į–į—Ā–į–Ĺ|–Ī—Ź–ľ–Ī–į)/i,
};
const parseDayPatterns = {
  narrow: [/^–Ĺ/i, /^–ī/i, /^–ľ/i, /^–Ľ/i, /^–Ņ/i, /^–Ī/i, /^–Ī/i],
  any: [/^–Ĺ—Ź/i, /^–ī–į/i, /^–ľ—Ź/i, /^–Ľ—Ö/i, /^–Ņ“Į/i, /^–Ī–į/i, /^–Ī—Ź/i],
};

const matchDayPeriodPatterns = {
  narrow: /^(“Į\.”©\.|“Į\.—Ö\.|—ą”©–Ĺ”© –ī—É–Ĺ–ī|“Į–ī –ī—É–Ĺ–ī|”©–≥–Ľ”©”©|”©–ī”©—Ä|–ĺ—Ä–ĺ–Ļ|—ą”©–Ĺ”©)/i,
  any: /^(“Į\.”©\.|“Į\.—Ö\.|—ą”©–Ĺ”© –ī—É–Ĺ–ī|“Į–ī –ī—É–Ĺ–ī|”©–≥–Ľ”©”©|”©–ī”©—Ä|–ĺ—Ä–ĺ–Ļ|—ą”©–Ĺ”©)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^“Į\.”©\./i,
    pm: /^“Į\.—Ö\./i,
    midnight: /^—ą”©–Ĺ”© –ī—É–Ĺ–ī/i,
    noon: /^“Į–ī –ī—É–Ĺ–ī/i,
    morning: /”©–≥–Ľ”©”©/i,
    afternoon: /”©–ī”©—Ä/i,
    evening: /–ĺ—Ä–ĺ–Ļ/i,
    night: /—ą”©–Ĺ”©/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
