const formatRelativeLocale = {
  lastWeek: (date) => {
    switch (date.getDay()) {
      case 0:
        return "'proŇ°lu nedjelju u' p";
      case 3:
        return "'proŇ°lu srijedu u' p";
      case 6:
        return "'proŇ°lu subotu u' p";
      default:
        return "'proŇ°li' EEEE 'u' p";
    }
  },
  yesterday: "'juńćer u' p",
  today: "'danas u' p",
  tomorrow: "'sutra u' p",
  nextWeek: (date) => {
    switch (date.getDay()) {
      case 0:
        return "'iduńáu nedjelju u' p";
      case 3:
        return "'iduńáu srijedu u' p";
      case 6:
        return "'iduńáu subotu u' p";
      default:
        return "'proŇ°li' EEEE 'u' p";
    }
  },
  other: "P",
};

export const formatRelative = (token, date, _baseDate, _options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date);
  }

  return format;
};
