function dateOrdinalNumber(number, localeNumber) {
  if (number > 18 && number <= 31) {
    return localeNumber + "ŗ¶∂ŗßá";
  } else {
    switch (number) {
      case 1:
        return localeNumber + "ŗ¶≤ŗ¶ĺ";
      case 2:
      case 3:
        return localeNumber + "ŗ¶įŗ¶ĺ";
      case 4:
        return localeNumber + "ŗ¶†ŗ¶ĺ";
      default:
        return localeNumber + "ŗ¶á";
    }
  }
}

const ordinalNumber = (dirtyNumber, options) => {
  const number = Number(dirtyNumber);
  const localeNumber = numberToLocale(number);
  const unit = options?.unit;

  if (unit === "date") {
    return dateOrdinalNumber(number, localeNumber);
  }
  if (number > 10 || number === 0) return localeNumber + "ŗ¶§ŗ¶ģ";

  const rem10 = number % 10;
  switch (rem10) {
    case 2:
    case 3:
      return localeNumber + "ŗßü";
    case 4:
      return localeNumber + "ŗ¶įŗßćŗ¶•";
    case 6:
      return localeNumber + "ŗ¶∑ŗßćŗ¶†";
    default:
      return localeNumber + "ŗ¶ģ";
  }
};

