const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "–Ņ–ĺ-–ľ–į–Ľ–ļ–ĺ –ĺ—ā —Ā–Ķ–ļ—É–Ĺ–ī–į",
    other: "–Ņ–ĺ-–ľ–į–Ľ–ļ–ĺ –ĺ—ā {{count}} —Ā–Ķ–ļ—É–Ĺ–ī–ł",
  },

  xSeconds: {
    one: "1 —Ā–Ķ–ļ—É–Ĺ–ī–į",
    other: "{{count}} —Ā–Ķ–ļ—É–Ĺ–ī–ł",
  },

  halfAMinute: "–Ņ–ĺ–Ľ–ĺ–≤–ł–Ĺ –ľ–ł–Ĺ—É—ā–į",

  lessThanXMinutes: {
    one: "–Ņ–ĺ-–ľ–į–Ľ–ļ–ĺ –ĺ—ā –ľ–ł–Ĺ—É—ā–į",
    other: "–Ņ–ĺ-–ľ–į–Ľ–ļ–ĺ –ĺ—ā {{count}} –ľ–ł–Ĺ—É—ā–ł",
  },

  xMinutes: {
    one: "1 –ľ–ł–Ĺ—É—ā–į",
    other: "{{count}} –ľ–ł–Ĺ—É—ā–ł",
  },

  aboutXHours: {
    one: "–ĺ–ļ–ĺ–Ľ–ĺ —á–į—Ā",
    other: "–ĺ–ļ–ĺ–Ľ–ĺ {{count}} —á–į—Ā–į",
  },

  xHours: {
    one: "1 —á–į—Ā",
    other: "{{count}} —á–į—Ā–į",
  },

  xDays: {
    one: "1 –ī–Ķ–Ĺ",
    other: "{{count}} –ī–Ĺ–ł",
  },

  aboutXWeeks: {
    one: "–ĺ–ļ–ĺ–Ľ–ĺ —Ā–Ķ–ī–ľ–ł—Ü–į",
    other: "–ĺ–ļ–ĺ–Ľ–ĺ {{count}} —Ā–Ķ–ī–ľ–ł—Ü–ł",
  },

  xWeeks: {
    one: "1 —Ā–Ķ–ī–ľ–ł—Ü–į",
    other: "{{count}} —Ā–Ķ–ī–ľ–ł—Ü–ł",
  },

  aboutXMonths: {
    one: "–ĺ–ļ–ĺ–Ľ–ĺ –ľ–Ķ—Ā–Ķ—Ü",
    other: "–ĺ–ļ–ĺ–Ľ–ĺ {{count}} –ľ–Ķ—Ā–Ķ—Ü–į",
  },

  xMonths: {
    one: "1 –ľ–Ķ—Ā–Ķ—Ü",
    other: "{{count}} –ľ–Ķ—Ā–Ķ—Ü–į",
  },

  aboutXYears: {
    one: "–ĺ–ļ–ĺ–Ľ–ĺ –≥–ĺ–ī–ł–Ĺ–į",
    other: "–ĺ–ļ–ĺ–Ľ–ĺ {{count}} –≥–ĺ–ī–ł–Ĺ–ł",
  },

  xYears: {
    one: "1 –≥–ĺ–ī–ł–Ĺ–į",
    other: "{{count}} –≥–ĺ–ī–ł–Ĺ–ł",
  },

  overXYears: {
    one: "–Ĺ–į–ī –≥–ĺ–ī–ł–Ĺ–į",
    other: "–Ĺ–į–ī {{count}} –≥–ĺ–ī–ł–Ĺ–ł",
  },

  almostXYears: {
    one: "–Ņ–ĺ—á—ā–ł –≥–ĺ–ī–ł–Ĺ–į",
    other: "–Ņ–ĺ—á—ā–ł {{count}} –≥–ĺ–ī–ł–Ĺ–ł",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return "—Ā–Ľ–Ķ–ī " + result;
    } else {
      return "–Ņ—Ä–Ķ–ī–ł " + result;
    }
  }

  return result;
};
