import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(th|st|nd|rd)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(Šěė\.)?ŠěāŠěü/i,
  abbreviated: /^(ŠěėŠěĽŠěď)?Šěā\.Šěü/i,
  wide: /^(ŠěėŠěĽŠěď|ŠěďŠüÉ)ŠěāŠüíŠěöŠě∑ŠěüŠüíŠěŹŠěüŠěÄŠěöŠě∂Šěá/i,
};
const parseEraPatterns = {
  any: [/^(Šěė|ŠěėŠěĽŠěď)Šěā\.?Šěü/i, /^(ŠěďŠüÉ)?Šěā\.?Šěü/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^q[1234]/i,
  wide: /^(ŠěŹŠüíŠěöŠěłŠěėŠě∂Šěü)(ŠěĎŠěł)?\s?[1234]/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^(Šěė\.ŠěÄ|ŠěÄ\.Šěė|ŠěėŠě∑|Šěė\.Šěü|Šěß\.Šěü|Šěė\.Šěź|ŠěÄ\.Šěä|ŠěüŠěł|ŠěÄŠěČ|ŠěŹŠěĽ|ŠěúŠě∑|Šěí)/i,
  abbreviated:
    /^(ŠěėŠěÄŠěöŠě∂|ŠěÄŠěĽŠěėŠüíŠěóŠüą|ŠěėŠěłŠěďŠě∂|ŠěėŠüĀŠěüŠě∂|ŠěßŠěüŠěóŠě∂|ŠěėŠě∑ŠěźŠěĽŠěďŠě∂|ŠěÄŠěÄŠüíŠěÄŠěäŠě∂|ŠěüŠěłŠě†Šě∂|ŠěÄŠěČŠüíŠěČŠě∂|ŠěŹŠěĽŠěõŠě∂|ŠěúŠě∑ŠěÖŠüíŠěÜŠě∑ŠěÄŠě∂|ŠěíŠüíŠěďŠěľ)/i,
  wide: /^(ŠěėŠěÄŠěöŠě∂|ŠěÄŠěĽŠěėŠüíŠěóŠüą|ŠěėŠěłŠěďŠě∂|ŠěėŠüĀŠěüŠě∂|ŠěßŠěüŠěóŠě∂|ŠěėŠě∑ŠěźŠěĽŠěďŠě∂|ŠěÄŠěÄŠüíŠěÄŠěäŠě∂|ŠěüŠěłŠě†Šě∂|ŠěÄŠěČŠüíŠěČŠě∂|ŠěŹŠěĽŠěõŠě∂|ŠěúŠě∑ŠěÖŠüíŠěÜŠě∑ŠěÄŠě∂|ŠěíŠüíŠěďŠěľ)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^Šěė\.ŠěÄ/i,
    /^ŠěÄ\.Šěė/i,
    /^ŠěėŠě∑/i,
    /^Šěė\.Šěü/i,
    /^Šěß\.Šěü/i,
    /^Šěė\.Šěź/i,
    /^ŠěÄ\.Šěä/i,
    /^ŠěüŠěł/i,
    /^ŠěÄŠěČ/i,
    /^ŠěŹŠěĽ/i,
    /^ŠěúŠě∑/i,
    /^Šěí/i,
  ],

  any: [
    /^ŠěėŠěÄ/i,
    /^ŠěÄŠěĽ/i,
    /^ŠěėŠěłŠěď/i,
    /^ŠěėŠüĀ/i,
    /^ŠěßŠěü/i,
    /^ŠěėŠě∑Šěź/i,
    /^ŠěÄŠěÄ/i,
    /^ŠěüŠěł/i,
    /^ŠěÄŠěČ/i,
    /^ŠěŹŠěĽ/i,
    /^ŠěúŠě∑ŠěÖ/i,
    /^Šěí/i,
  ],
};

const matchDayPatterns = {
  narrow: /^(ŠěĘŠě∂|ŠěÖ|ŠěĘ|ŠěĖ|ŠěĖŠüíŠěö|ŠěüŠěĽ|Šěü)/i,
  short: /^(ŠěĘŠě∂|ŠěÖ|ŠěĘ|ŠěĖ|ŠěĖŠüíŠěö|ŠěüŠěĽ|Šěü)/i,
  abbreviated: /^(ŠěĘŠě∂|ŠěÖ|ŠěĘ|ŠěĖ|ŠěĖŠüíŠěö|ŠěüŠěĽ|Šěü)/i,
  wide: /^(ŠěĘŠě∂ŠěĎŠě∑ŠěŹŠüíŠěô|ŠěÖŠěďŠüíŠěĎ|ŠěĘŠěĄŠüíŠěāŠě∂Šěö|ŠěĖŠěĽŠěí|ŠěĖŠüíŠěöŠě†ŠěüŠüíŠěĒŠěŹŠě∑Šüć|ŠěüŠěĽŠěÄŠüíŠěö|ŠěüŠüÖŠěöŠüć)/i,
};
const parseDayPatterns = {
  narrow: [/^ŠěĘŠě∂/i, /^ŠěÖ/i, /^ŠěĘ/i, /^ŠěĖ/i, /^ŠěĖŠüíŠěö/i, /^ŠěüŠěĽ/i, /^Šěü/i],
  any: [/^ŠěĘŠě∂/i, /^ŠěÖ/i, /^ŠěĘ/i, /^ŠěĖ/i, /^ŠěĖŠüíŠěö/i, /^ŠěüŠěĽ/i, /^ŠěüŠüÖ/i],
};

const matchDayPeriodPatterns = {
  narrow:
    /^(ŠěĖŠüíŠěöŠěĻŠěÄ|ŠěõŠüíŠěĄŠě∂ŠěÖ|ŠěĖŠüĀŠěõŠěĖŠüíŠěöŠěĻŠěÄ|ŠěĖŠüĀŠěõŠěźŠüíŠěĄŠüÉŠěŹŠüíŠěöŠěĄŠüč|ŠěĖŠüĀŠěõŠěõŠüíŠěĄŠě∂ŠěÖ|ŠěĖŠüĀŠěõŠěöŠěüŠüÄŠěõ|ŠěĖŠüĀŠěõŠěôŠěĒŠüč|ŠěĖŠüĀŠěõŠěÄŠěéŠüíŠěäŠě∂ŠěõŠěĘŠěíŠüíŠěöŠě∂ŠěŹŠüíŠěö)/i,
  any: /^(ŠěĖŠüíŠěöŠěĻŠěÄ|ŠěõŠüíŠěĄŠě∂ŠěÖ|ŠěĖŠüĀŠěõŠěĖŠüíŠěöŠěĻŠěÄ|ŠěĖŠüĀŠěõŠěźŠüíŠěĄŠüÉŠěŹŠüíŠěöŠěĄŠüč|ŠěĖŠüĀŠěõŠěõŠüíŠěĄŠě∂ŠěÖ|ŠěĖŠüĀŠěõŠěöŠěüŠüÄŠěõ|ŠěĖŠüĀŠěõŠěôŠěĒŠüč|ŠěĖŠüĀŠěõŠěÄŠěéŠüíŠěäŠě∂ŠěõŠěĘŠěíŠüíŠěöŠě∂ŠěŹŠüíŠěö)/i,
};

const parseDayPeriodPatterns = {
  any: {
    am: /^ŠěĖŠüíŠěöŠěĻŠěÄ/i,
    pm: /^ŠěõŠüíŠěĄŠě∂ŠěÖ/i,
    midnight: /^ŠěĖŠüĀŠěõŠěÄŠěéŠüíŠěäŠě∂ŠěõŠěĘŠěíŠüíŠěöŠě∂ŠěŹŠüíŠěö/i,
    noon: /^ŠěĖŠüĀŠěõŠěźŠüíŠěĄŠüÉŠěŹŠüíŠěöŠěĄŠüč/i,
    morning: /ŠěĖŠüĀŠěõŠěĖŠüíŠěöŠěĻŠěÄ/i,
    afternoon: /ŠěĖŠüĀŠěõŠěöŠěüŠüÄŠěõ/i,
    evening: /ŠěĖŠüĀŠěõŠěõŠüíŠěĄŠě∂ŠěÖ/i,
    night: /ŠěĖŠüĀŠěõŠěôŠěĒŠüč/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: function (value) {
      return parseInt(value, 10);
    },
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
