const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "1 —Ā–ĺ–Ĺ–ł—Ź–ī–į–Ĺ –ļ–į–ľ",
    other: "{{count}} —Ā–ĺ–Ĺ–ł—Ź–ī–į–Ĺ –ļ–į–ľ",
  },

  xSeconds: {
    one: "1 —Ā–ĺ–Ĺ–ł—Ź",
    other: "{{count}} —Ā–ĺ–Ĺ–ł—Ź",
  },

  halfAMinute: "—Ź—Ä–ł–ľ –ī–į“õ–ł“õ–į",

  lessThanXMinutes: {
    one: "1 –ī–į“õ–ł“õ–į–ī–į–Ĺ –ļ–į–ľ",
    other: "{{count}} –ī–į“õ–ł“õ–į–ī–į–Ĺ –ļ–į–ľ",
  },

  xMinutes: {
    one: "1 –ī–į“õ–ł“õ–į",
    other: "{{count}} –ī–į“õ–ł“õ–į",
  },

  aboutXHours: {
    one: "—ā–į—Ö–ľ–ł–Ĺ–į–Ĺ 1 —Ā–ĺ–į—ā",
    other: "—ā–į—Ö–ľ–ł–Ĺ–į–Ĺ {{count}} —Ā–ĺ–į—ā",
  },

  xHours: {
    one: "1 —Ā–ĺ–į—ā",
    other: "{{count}} —Ā–ĺ–į—ā",
  },

  xDays: {
    one: "1 –ļ—É–Ĺ",
    other: "{{count}} –ļ—É–Ĺ",
  },

  aboutXWeeks: {
    one: "—ā–į—Ö–ľ–ł–Ĺ–į–Ĺ 1 —Ö–į—Ą—ā–į",
    other: "—ā–į—Ö–ľ–ł–Ĺ–į–Ĺ {{count}} —Ö–į—Ą—ā–į",
  },

  xWeeks: {
    one: "1 —Ö–į—Ą—ā–į",
    other: "{{count}} —Ö–į—Ą—ā–į",
  },

  aboutXMonths: {
    one: "—ā–į—Ö–ľ–ł–Ĺ–į–Ĺ 1 –ĺ–Ļ",
    other: "—ā–į—Ö–ľ–ł–Ĺ–į–Ĺ {{count}} –ĺ–Ļ",
  },

  xMonths: {
    one: "1 –ĺ–Ļ",
    other: "{{count}} –ĺ–Ļ",
  },

  aboutXYears: {
    one: "—ā–į—Ö–ľ–ł–Ĺ–į–Ĺ 1 –Ļ–ł–Ľ",
    other: "—ā–į—Ö–ľ–ł–Ĺ–į–Ĺ {{count}} –Ļ–ł–Ľ",
  },

  xYears: {
    one: "1 –Ļ–ł–Ľ",
    other: "{{count}} –Ļ–ł–Ľ",
  },

  overXYears: {
    one: "1 –Ļ–ł–Ľ–ī–į–Ĺ –ļ—ě–Ņ",
    other: "{{count}} –Ļ–ł–Ľ–ī–į–Ĺ –ļ—ě–Ņ",
  },

  almostXYears: {
    one: "–ī–Ķ—Ź—Ä–Ľ–ł 1 –Ļ–ł–Ľ",
    other: "–ī–Ķ—Ź—Ä–Ľ–ł {{count}} –Ļ–ł–Ľ",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return result + "–ī–į–Ĺ –ļ–Ķ–Ļ–ł–Ĺ";
    } else {
      return result + " –ĺ–Ľ–ī–ł–Ĺ";
    }
  }

  return result;
};
