import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)\./i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(p\.m\.ńď|m\.ńď)/i,
  abbreviated: /^(p\. m\. ńď\.|m\. ńď\.)/i,
  wide: /^(pirms mŇęsu ńďras|mŇęsu ńďrńĀ)/i,
};
const parseEraPatterns = {
  any: [/^p/i, /^m/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](\. cet\.)/i,
  wide: /^(pirma(is|jńĀ)|otra(is|jńĀ)|treŇ°a(is|jńĀ)|ceturta(is|jńĀ)) ceturksn(is|ńę)/i,
};
const parseQuarterPatterns = {
  narrow: [/^1/i, /^2/i, /^3/i, /^4/i],
  abbreviated: [/^1/i, /^2/i, /^3/i, /^4/i],
  wide: [/^p/i, /^o/i, /^t/i, /^c/i],
};

const matchMonthPatterns = {
  narrow: /^[jfmasond]/i,
  abbreviated:
    /^(janv\.|febr\.|marts|apr\.|maijs|jŇęn\.|jŇęl\.|aug\.|sept\.|okt\.|nov\.|dec\.)/i,
  wide: /^(janvńĀr(is|ńę)|februńĀr(is|ńę)|mart[sńĀ]|aprńęl(is|ńę)|maij[sńĀ]|jŇęnij[sńĀ]|jŇęlij[sńĀ]|august[sńĀ]|septembr(is|ńę)|oktobr(is|ńę)|novembr(is|ńę)|decembr(is|ńę))/i,
};
const parseMonthPatterns = {
  narrow: [
    /^j/i,
    /^f/i,
    /^m/i,
    /^a/i,
    /^m/i,
    /^j/i,
    /^j/i,
    /^a/i,
    /^s/i,
    /^o/i,
    /^n/i,
    /^d/i,
  ],

  any: [
    /^ja/i,
    /^f/i,
    /^mar/i,
    /^ap/i,
    /^mai/i,
    /^jŇęn/i,
    /^jŇęl/i,
    /^au/i,
    /^s/i,
    /^o/i,
    /^n/i,
    /^d/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[spotc]/i,
  short: /^(sv|pi|o|t|c|pk|s)/i,
  abbreviated: /^(svńďtd\.|pirmd\.|otrd.\|treŇ°d\.|ceturtd\.|piektd\.|sestd\.)/i,
  wide: /^(svńďtdien(a|ńĀ)|pirmdien(a|ńĀ)|otrdien(a|ńĀ)|treŇ°dien(a|ńĀ)|ceturtdien(a|ńĀ)|piektdien(a|ńĀ)|sestdien(a|ńĀ))/i,
};
const parseDayPatterns = {
  narrow: [/^s/i, /^p/i, /^o/i, /^t/i, /^c/i, /^p/i, /^s/i],
  any: [/^sv/i, /^pi/i, /^o/i, /^t/i, /^c/i, /^p/i, /^se/i],
};

const matchDayPeriodPatterns = {
  narrow: /^(am|pm|pusn\.|pusd\.|rńęt(s|ńĀ)|dien(a|ńĀ)|vakar(s|ńĀ)|nakt(s|ńę))/,
  abbreviated: /^(am|pm|pusn\.|pusd\.|rńęt(s|ńĀ)|pńďcpusd\.|vakar(s|ńĀ)|nakt(s|ńę))/,
  wide: /^(am|pm|pusnakt(s|ńę)|pusdienlaik(s|ńĀ)|rńęt(s|ńĀ)|pńďcpusdien(a|ńĀ)|vakar(s|ńĀ)|nakt(s|ńę))/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^am/i,
    pm: /^pm/i,
    midnight: /^pusn/i,
    noon: /^pusd/i,
    morning: /^r/i,
    afternoon: /^(d|pńďc)/i,
    evening: /^v/i,
    night: /^n/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "wide",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
